('en', 'B1', 'listening', 'The Bustling Station', 'Listen to the sounds of a railway station', '{"type":"listen_and_choose","instructions":"Listen to the sound description and choose the correct interpretation.","exercises":[{"prompt":"The sharp whistle of a steam engine echoed through the vaulted ceiling.","options":["🚆 Train","🛳️ Ship","✈️ Plane","🚗 Car"],"correct":0,"hint":"Sharp steam whistle"},{"prompt":"The rhythmic clatter of wheels on tracks grew louder.","options":["🚲 Cycle","🚃 Train","🚜 Tractor","🚁 Drone"],"correct":1,"hint":"Wheels on tracks"},{"prompt":"Announcement: The 10:15 to London is now boarding at platform four.","options":["🏨 Hotel","🏢 Office","🚉 Station","🏫 School"],"correct":2,"hint":"Platform 4"},{"prompt":"Muffled chatter of hundreds of travelers in the waiting room.","options":["🎭 Theater","🏛️ Museum","🚉 Hall","🌳 Park"],"correct":2,"hint":"Travelers in hall"},{"prompt":"Scraping sound of heavy suitcases being dragged.","options":["🧳 Luggage","🧹 Cleaning","🔨 Construction","🎹 Piano"],"correct":0,"hint":"Dragging suitcases"},{"prompt":"The distant roar of a jet engine filled the sky.","options":["🚁 Helicopter","✈️ Plane","🚢 Boat","🚙 Van"],"correct":1,"hint":"Roaring jet engine"},{"prompt":"The soft rustle of leaves could be heard in the gentle breeze.","options":["🌳 Forest","🏖️ Beach","🏜️ Desert","🏙️ City"],"correct":0,"hint":"Leaves rustling"},{"prompt":"The blaring horn of a bus sounded as it approached the stop.","options":["🚍 Bus","🚗 Car","🚙 Van","🚓 Police Car"],"correct":0,"hint":"Blaring bus horn"},{"prompt":"The clickety-clack of a typewriter filled the quiet room.","options":["🖥️ Computer","✉️ Mailbox","📜 Scroll","⌨️ Typewriter"],"correct":3,"hint":"Typewriter sound"},{"prompt":"The gentle bubbling of water boiling on the stove was calming.","options":["🍽️ Kitchen","🌊 Ocean","🏞️ River","🌋 Volcano"],"correct":0,"hint":"Bubbling water"},{"prompt":"The sharp crack of thunder echoed across the valley.","options":["⚡ Lightning","🌩️ Storm","☀️ Sun","🌈 Rainbow"],"correct":1,"hint":"Crack of thunder"},{"prompt":"The loud screech of tires signaled an emergency stop.","options":["🚗 Car","🚲 Bicycle","🚚 Truck","🚓 Police Car"],"correct":0,"hint":"Screeching tires"},{"prompt":"The cheerful chirping of birds filled the morning air.","options":["🐦 Birds","🐶 Dogs","🐱 Cats","🐰 Rabbits"],"correct":0,"hint":"Chirping birds"},{"prompt":"The distant sound of waves crashing against the shore was soothing.","options":["🏝️ Island","🏖️ Beach","🌊 Ocean","🪴 Forest"],"correct":1,"hint":"Waves crashing"},{"prompt":"The metallic clang of a construction site echoed through the streets.","options":["🏗️ Construction","🏢 Office","🏬 Mall","🏪 Store"],"correct":0,"hint":"Clang of metal"},{"prompt":"The rhythmic beating of drums resonated through the crowd.","options":["🎸 Guitar","🥁 Drums","🎻 Violin","🎤 Microphone"],"correct":1,"hint":"Beating drums"},{"prompt":"The soft ticking of a clock marked the passage of time.","options":["⌚ Watch","🕰️ Clock","📅 Calendar","📖 Book"],"correct":1,"hint":"Ticking clock"},{"prompt":"The loud laughter of children playing filled the park.","options":["🏫 School","🏖️ Playground","🌳 Park","🏠 House"],"correct":2,"hint":"Children laughing"},{"prompt":"The eerie howl of the wind sent shivers down my spine.","options":["🌪️ Tornado","🌬️ Wind","🌈 Rainbow","☀️ Sun"],"correct":1,"hint":"Howling wind"}]}', 11),
('en', 'B1', 'listening', 'City Rhythms', 'Identify the layered sounds of an urban environment', '{"type":"listen_and_choose","instructions":"Identify the primary urban sound described.","exercises":[{"prompt":"The distant wail of a siren cut through the midnight silence.","options":["🚑 Siren","🎶 Concert","🌬️ Wind","🐶 Dog"],"correct":0,"hint":"Emergency wail"},{"prompt":"The steady hum of traffic on the highway below.","options":["🐝 Bees","🚗 Cars","🌊 Waves","📻 Radio"],"correct":1,"hint":"Highway hum"},{"prompt":"The bright jingle of a bicycle bell.","options":["🔔 Bell","🚪 Doorbell","📱 Phone","🎸 Guitar"],"correct":0,"hint":"Cyclist warning"},{"prompt":"The heavy thud of a pile driver at a construction site.","options":["🔨 Construction","🌩️ Thunder","🥁 Drums","🏀 Ball"],"correct":0,"hint":"Construction thud"},{"prompt":"The melodic chirping of birds in the city park at sunrise.","options":["🐦 Birds","🦗 Crickets","🐈 Cats","🐒 Monkeys"],"correct":0,"hint":"Morning birds"},{"prompt":"The rhythmic clatter of subway trains arriving at the station.","options":["🚆 Subway","🚕 Taxi","🚌 Bus","🚙 Car"],"correct":0,"hint":"Underground transit"},{"prompt":"The cheerful chirping of birds in the early morning.","options":["🐦 Birds","🐕 Dog","🚗 Car","📦 Package"],"correct":0,"hint":"Morning melody"},{"prompt":"The loud thump of bass from a nearby nightclub.","options":["🎶 Concert","🎧 Music","📻 Radio","🔊 Bass"],"correct":3,"hint":"Nightlife sound"},{"prompt":"The rapid clicking of heels on pavement as people walk by.","options":["👠 Heels","👟 Sneakers","🥿 Flats","👢 Sandals"],"correct":0,"hint":"City stride"},{"prompt":"The loud honk of a taxi as it weaves through traffic.","options":["🚕 Taxi","🚗 Car","🚦 Traffic light","🚙 SUV"],"correct":0,"hint":"Cabbie call"},{"prompt":"The soft rustle of leaves in the park on a windy day.","options":["🍂 Leaves","🌊 Waves","🌬️ Wind","🐦 Birds"],"correct":0,"hint":"Nature''s whisper"},{"prompt":"The distant roar of an airplane flying overhead.","options":["✈️ Airplane","🚗 Car","🎶 Music","🚆 Train"],"correct":0,"hint":"Sky travel"},{"prompt":"The lively chatter of people at a bustling café.","options":["☕ Coffee","🗣️ Conversation","🎶 Music","📖 Book"],"correct":1,"hint":"Social buzz"},{"prompt":"The jarring clang of construction work on a nearby building.","options":["🔨 Hammer","🚧 Construction","📦 Delivery","🎉 Celebration"],"correct":1,"hint":"Urban development"},{"prompt":"The gentle trickle of water from a nearby fountain.","options":["💧 Water","🐦 Birds","🚗 Car","🎶 Music"],"correct":0,"hint":"Water feature"},{"prompt":"The loud clanging of a bell signaling the end of the workday.","options":["🔔 Bell","📱 Phone","🚦 Traffic light","🎶 Music"],"correct":0,"hint":"End of shift"},{"prompt":"The soft ping of a text alert from a nearby smartphone.","options":["🔔 Notification","🎵 Music","🚪 Doorbell","🛎️ Service bell"],"correct":0,"hint":"Digital alert"},{"prompt":"The loud crackle of fireworks during a holiday celebration.","options":["🎇 Fireworks","🎶 Concert","🎉 Party","🧨 Explosions"],"correct":0,"hint":"Celebratory boom"},{"prompt":"The soft pitter-patter of rain on a city sidewalk.","options":["🌧️ Rain","🌊 Waves","🐦 Birds","🚗 Car"],"correct":0,"hint":"Weather sound"},{"prompt":"The distant thud of a basketball hitting the court at a nearby park.","options":["🏀 Basketball","🎶 Music","📦 Package","🚗 Car"],"correct":0,"hint":"Sporting activity"}]}', 12),
('en', 'B1', 'listening', 'Nature Symphony', 'Listen to natural audio landscapes', '{"type":"listen_and_choose","instructions":"Match the sound description to the image.","exercises":[{"prompt":"The thunderous roar of a waterfall.","options":["🌊 Waterfall","🌧️ Rain","🥤 Drink","🛁 Shower"],"correct":0,"hint":"Roaring water"},{"prompt":"The gentle rustle of dry leaves underfoot.","options":["🍂 Leaves","🔥 Fire","🍿 Popcorn","📄 Paper"],"correct":0,"hint":"Autumn rustle"},{"prompt":"The crashing of waves against jagged rocks.","options":["🌊 Sea","🚿 Shower","☕ Coffee","🍵 Tea"],"correct":0,"hint":"Breaking waves"},{"prompt":"The crackling of a campfire in the silent wilderness.","options":["🔥 Campfire","🎆 Fireworks","🔫 Gunshot","🍳 Pan"],"correct":0,"hint":"Crackling wood"},{"prompt":"The howling wind during a blizzard.","options":["❄️ Blizzard","🦁 Lion","🚗 Car","🚂 Train"],"correct":0,"hint":"Howling cold"},{"prompt":"The soft purring of a content cat.","options":["🐱 Cat","🐶 Dog","🐦 Bird","🐍 Snake"],"correct":0,"hint":"Happy feline sound"},{"prompt":"The crackling of a warm fire.","options":["🔥 Fire","🌪️ Wind","🚪 Door","🕯️ Candle"],"correct":0,"hint":"Cozy flames"},{"prompt":"The chirping of birds at dawn.","options":["🐦 Birds","🔔 Bell","🦋 Butterfly","🌼 Flower"],"correct":0,"hint":"Morning melody"},{"prompt":"The honking of a car horn.","options":["🚗 Car","🚲 Bicycle","🚌 Bus","🏍️ Motorcycle"],"correct":0,"hint":"Traffic signal sound"},{"prompt":"The buzzing of a busy bee.","options":["🐝 Bee","🐞 Ladybug","🦋 Butterfly","🦟 Mosquito"],"correct":0,"hint":"Pollinator''s hum"},{"prompt":"The rustling of fabric in the wind.","options":["🧥 Jacket","🌬️ Wind","🎈 Balloon","🕶️ Sunglasses"],"correct":0,"hint":"Cloth in motion"},{"prompt":"The distant howl of a wolf.","options":["🐺 Wolf","🐻 Bear","🐼 Panda","🐾 Paw"],"correct":0,"hint":"Nature''s call"},{"prompt":"The soft drip of rain on a window.","options":["🌧️ Rain","☔ Umbrella","🌈 Rainbow","🌪️ Tornado"],"correct":0,"hint":"Gentle weather"},{"prompt":"The thud of a basketball hitting the court.","options":["🏀 Basketball","⚽ Soccer ball","🏈 Football","🎾 Tennis ball"],"correct":0,"hint":"Sporting sound"},{"prompt":"The distant rumble of thunder.","options":["⛈️ Thunder","🌪️ Wind","🌧️ Rain","🌈 Rainbow"],"correct":0,"hint":"Stormy sign"},{"prompt":"The crack of a bat hitting a baseball.","options":["⚾ Baseball","🏀 Basketball","🏈 Football","🎾 Tennis"],"correct":0,"hint":"Game time"},{"prompt":"The rhythmic ticking of a clock.","options":["⏰ Clock","🎶 Music","📖 Book","🖥️ Computer"],"correct":0,"hint":"Time keeper"},{"prompt":"The bubbling of water on a stove.","options":["🍳 Cooking","🍞 Baking","🥗 Mixing","🍲 Stewing"],"correct":0,"hint":"Boiling sound"},{"prompt":"The rustle of a newspaper being read.","options":["📰 Newspaper","📚 Book","📖 Magazine","📜 Scroll"],"correct":0,"hint":"Reading sound"},{"prompt":"The clinking of glasses during a toast.","options":["🥂 Glasses","🍽️ Plates","🍷 Wine","🍻 Beer"],"correct":0,"hint":"Celebration sound"}]}', 13),
('en', 'B1', 'listening', 'Workplace Atmosphere', 'Identify sounds in a modern office', '{"type":"listen_and_choose","instructions":"Choose the equipment based on the sound.","exercises":[{"prompt":"The rapid-fire clicking of mechanical keyboards.","options":["💻 Keyboards","🖱️ Mice","⏰ Clocks","🔨 Hammers"],"correct":0,"hint":"Key clicking"},{"prompt":"The whirring and beeping of the photocopier.","options":["📠 Copier","📠 Fax","☕ Coffee","🌬️ Fan"],"correct":0,"hint":"Copier whirring"},{"prompt":"The soft chime of an incoming video call.","options":["💻 Video call","🔔 Doorbell","⏰ Alarm","📢 Announcement"],"correct":0,"hint":"Call chime"},{"prompt":"The hiss of the espresso machine in the breakroom.","options":["☕ Espresso","🐍 Snake","🎈 Balloon","🚿 Shower"],"correct":0,"hint":"Steaming coffee"},{"prompt":"The low murmur of colleagues in a meeting.","options":["👥 Meeting","🎤 Concert","📣 Protest","🤫 Secret"],"correct":0,"hint":"Talking colleagues"},{"prompt":"The rhythmic tapping of a drum set.","options":["🥁 Drums","🎸 Guitar","🎤 Microphone","🎻 Violin"],"correct":0,"hint":"Percussion sound"},{"prompt":"The buzzing sound of a smartphone notification.","options":["📱 Smartphone","🔊 Speaker","🎧 Headphones","📡 Router"],"correct":0,"hint":"Notification buzz"},{"prompt":"The grinding noise of a coffee grinder.","options":["☕ Coffee grinder","🍞 Toaster","🍽️ Dishwasher","🍳 Frying pan"],"correct":0,"hint":"Grinding coffee"},{"prompt":"The loud roar of a jet engine.","options":["✈️ Jet","🚗 Car","🚂 Train","🚢 Ship"],"correct":0,"hint":"Airplane noise"},{"prompt":"The gentle rustle of pages being turned.","options":["📖 Book","📚 Notebook","📰 Newspaper","📒 Journal"],"correct":0,"hint":"Page turning"},{"prompt":"The clinking of ice cubes in a glass.","options":["🥤 Drink","🍹 Cocktail shaker","🍷 Wine bottle","🍺 Beer can"],"correct":0,"hint":"Ice clinking"},{"prompt":"The sound of a camera shutter clicking.","options":["📷 Camera","📹 Video recorder","🎥 Projector","📺 TV"],"correct":0,"hint":"Shutter click"},{"prompt":"The chirping of birds in the morning.","options":["🐦 Birds","🐶 Dog","🐱 Cat","🐮 Cow"],"correct":0,"hint":"Morning chirping"},{"prompt":"The loud beep of a microwave finishing.","options":["🍽️ Microwave","🍳 Stove","🥘 Oven","🍕 Pizza box"],"correct":0,"hint":"Microwave beep"},{"prompt":"The crunching sound of leaves underfoot.","options":["🍂 Leaves","👣 Feet","🏞️ Grass","🪨 Rocks"],"correct":0,"hint":"Leaves crunching"},{"prompt":"The soft splashing of water in a fountain.","options":["⛲ Fountain","💧 Raindrops","🚿 Shower","🌊 Ocean waves"],"correct":0,"hint":"Water splashing"},{"prompt":"The buzzing of a bee flying nearby.","options":["🐝 Bee","🦋 Butterfly","🐞 Ladybug","🦟 Mosquito"],"correct":0,"hint":"Bee buzzing"},{"prompt":"The crackling sound of a campfire.","options":["🔥 Campfire","🌪️ Wind","🌧️ Rain","💨 Air"],"correct":0,"hint":"Fire crackling"},{"prompt":"The soft purring of a cat.","options":["🐱 Cat","🐶 Dog","🐰 Rabbit","🐦 Bird"],"correct":0,"hint":"Cat sound"},{"prompt":"The loud honking of a car horn.","options":["🚗 Car horn","🚲 Bicycle bell","🚦 Traffic light","🚧 Construction"],"correct":0,"hint":"Car honking"}]}', 14),
('en', 'B1', 'listening', 'The Kitchen Ballet', 'Sounds of cooking a complex meal', '{"type":"listen_and_choose","instructions":"Identify the kitchen activity.","exercises":[{"prompt":"The rhythmic chopping of vegetables.","options":["🔪 Chopping","🥣 Stirring","🔥 Frying","🧂 Seasoning"],"correct":0,"hint":"Knife on board"},{"prompt":"The aggressive sizzle of a steak.","options":["🥩 Steak","🍲 Soup","🧊 Ice","🍞 Toast"],"correct":0,"hint":"Hot skillet sizzle"},{"prompt":"The metallic clink of a whisk against a glass bowl.","options":["🥚 Whisking","🥄 Eating","🍽️ Table","🍷 Wine"],"correct":0,"hint":"Beating eggs"},{"prompt":"The high-pitched whistle of a teakettle.","options":["🫖 Teakettle","🚂 Train","🌬️ Wind","🐦 Bird"],"correct":0,"hint":"Boiling water"},{"prompt":"The satisfying pop of a wine cork.","options":["🍾 Cork","🎈 Balloon","💥 Firework","🔫 Toy"],"correct":0,"hint":"Opening bottle"},{"prompt":"The gentle bubbling of pasta boiling.","options":["🍝 Boiling","🥘 Steaming","🍳 Scrambling","🥗 Mixing"],"correct":0,"hint":"Water in a pot"},{"prompt":"The soft thud of bread being kneaded.","options":["🍞 Kneading","🍪 Baking","🧄 Chopping","🍰 Icing"],"correct":0,"hint":"Dough on a surface"},{"prompt":"The soothing sound of ice cubes clinking in a glass.","options":["🧊 Chilling","🥤 Pouring","🍸 Mixing","🍾 Opening"],"correct":0,"hint":"Iced drink preparation"},{"prompt":"The crackling sound of bacon in a pan.","options":["🥓 Frying","🍳 Boiling","🍚 Steaming","🍖 Roasting"],"correct":0,"hint":"Hot oil sound"},{"prompt":"The rhythmic stirring of a pot of soup.","options":["🥣 Stirring","🔥 Sizzling","🍽️ Serving","🍜 Boiling"],"correct":0,"hint":"Wooden spoon sound"},{"prompt":"The sharp clatter of a knife on a cutting board.","options":["🔪 Chopping","🧂 Seasoning","🍳 Frying","🥗 Tossing"],"correct":0,"hint":"Prep work noise"},{"prompt":"The soft popping sound of popcorn.","options":["🍿 Popping","🍪 Baking","🥳 Celebrating","🍕 Slicing"],"correct":0,"hint":"Snack time"},{"prompt":"The gentle splash of oil in a hot pan.","options":["🧴 Pouring","🍳 Frying","🥩 Grilling","🍕 Cooking"],"correct":0,"hint":"Cooking preparation"},{"prompt":"The crunch of fresh vegetables being diced.","options":["🥒 Dicing","🍅 Chopping","🌶️ Grating","🍆 Mixing"],"correct":0,"hint":"Knife on veggies"},{"prompt":"The sound of a blender whirring.","options":["🍹 Blending","🥄 Mixing","🍽️ Serving","🍵 Steeping"],"correct":0,"hint":"Smoothie time"},{"prompt":"The fizz of soda being poured into a glass.","options":["🥤 Pouring","🍵 Brewing","🍸 Mixing","🍷 Sipping"],"correct":0,"hint":"Carbonated drink"},{"prompt":"The sound of a can opening with a pop.","options":["🥫 Opening","🍾 Pouring","🍵 Steeping","🍧 Chilling"],"correct":0,"hint":"Canned goods"},{"prompt":"The soft sound of butter melting in a pan.","options":["🧈 Melting","🍳 Frying","🍔 Grilling","🍕 Baking"],"correct":0,"hint":"Cooking fat"},{"prompt":"The sound of a cork popping from a bottle.","options":["🍾 Opening","🍷 Pouring","🍹 Mixing","🥃 Tasting"],"correct":0,"hint":"Celebratory drink"},{"prompt":"The sound of a timer ringing in the kitchen.","options":["⏰ Timing","🍳 Cooking","🍰 Baking","🥣 Mixing"],"correct":0,"hint":"Countdown finished"}]}', 15),
('en', 'B1', 'listening', 'Evening Entertainment', 'Sounds from a theater', '{"type":"listen_and_choose","instructions":"Identify the performance sound.","exercises":[{"prompt":"The collective gasp of the audience.","options":["😲 Gasping","👏 Clapping","😂 Laughing","😢 Crying"],"correct":0,"hint":"Surprised audience"},{"prompt":"An orchestra tuning their instruments.","options":["🎻 Tuning","🎼 Playing","👏 Applauding","🤫 Shushing"],"correct":0,"hint":"Before playing"},{"prompt":"Thunderous applause as the curtain fell.","options":["👏 Applause","🌧️ Thunder","🌊 Waves","🚁 Helicopter"],"correct":0,"hint":"End of show"},{"prompt":"Delicate tinkling of a piano sonata.","options":["🎹 Piano","🎻 Violin","🎺 Trumpet","🥁 Drums"],"correct":0,"hint":"Piano keys"},{"prompt":"Muffled laughter ripples through the rows.","options":["🎭 Comedy","🏟️ Match","🏥 Hospital","🏦 Bank"],"correct":0,"hint":"Funny moment"},{"prompt":"The sound of a conductor''s baton hitting the music stand.","options":["🎶 Baton Tap","📯 Horn Blowing","🎷 Saxophone","👂 Whispering"],"correct":0,"hint":"Starting the performance"},{"prompt":"The rustle of programs being opened.","options":["📜 Rustling","🎤 Singing","🥁 Drumming","🎸 Strumming"],"correct":0,"hint":"Audience preparation"},{"prompt":"A performer taking a deep breath before singing.","options":["😮 Inhaling","😂 Laughing","👏 Applauding","🤫 Shushing"],"correct":0,"hint":"Nervous anticipation"},{"prompt":"The soft hum of the audience waiting in silence.","options":["🤫 Humming","🎶 Playing","🗣️ Talking","😢 Crying"],"correct":0,"hint":"Before the show starts"},{"prompt":"The sound of footsteps on the stage.","options":["👣 Footsteps","🚪 Door Opening","🎹 Piano Playing","🎤 Microphone Feedback"],"correct":0,"hint":"Entering the stage"},{"prompt":"The sound of a violin string being bowed.","options":["🎻 Bowing","🥁 Tapping","🎺 Trumpeting","🎷 Saxing"],"correct":0,"hint":"String instrument"},{"prompt":"The murmur of excitement as the lights dim.","options":["🤫 Murmuring","😲 Gasping","😂 Laughing","👋 Waving"],"correct":0,"hint":"Audience reacting"},{"prompt":"The first note of a piano ringing out.","options":["🎹 Playing","🎸 Strumming","🎻 Tuning","📯 Blowing"],"correct":0,"hint":"Beginning of music"},{"prompt":"The clinking of glasses during a toast.","options":["🥂 Clinking","🎤 Singing","🎻 Playing","🤫 Shushing"],"correct":0,"hint":"Celebration moment"},{"prompt":"The sound of a drumroll before a big reveal.","options":["🥁 Drumroll","🎤 Singing","📯 Horn Blowing","👂 Whispering"],"correct":0,"hint":"Building suspense"},{"prompt":"The sound of a microphone being adjusted.","options":["🎤 Adjusting","🎸 Strumming","🎹 Playing","🎻 Tuning"],"correct":0,"hint":"Before speaking"},{"prompt":"The sound of a soloist''s voice echoing in the hall.","options":["🎤 Singing","🎶 Playing","🚪 Door Closing","🗣️ Talking"],"correct":0,"hint":"Highlight of the performance"},{"prompt":"The soft sound of a flute playing a melody.","options":["🎶 Flute","🥁 Drumming","🎹 Piano","🎻 Violin"],"correct":0,"hint":"Woodwind instrument"},{"prompt":"The sound of laughter from the audience.","options":["😂 Laughing","😲 Gasping","🤫 Shushing","👏 Applauding"],"correct":0,"hint":"Joyful reaction"},{"prompt":"The sound of a soloist taking a bow.","options":["👏 Applause","🎤 Singing","🤫 Shushing","🎻 Tuning"],"correct":0,"hint":"Acknowledging the audience"}]}', 16),
('en', 'B1', 'listening', 'Morning at Home', 'Daily routine sounds', '{"type":"listen_and_choose","instructions":"What part of the morning is this?","exercises":[{"prompt":"The persistent buzzing of an alarm clock.","options":["⏰ Waking","☕ Breakfast","🚿 Shower","🚗 Travel"],"correct":0,"hint":"Buzzing alarm"},{"prompt":"The gushing sound of the shower.","options":["🚿 Shower","🌧️ Rain","🌊 Swimming","☕ Drink"],"correct":0,"hint":"Water in bathroom"},{"prompt":"Scraping a knife spreading butter on toast.","options":["🍞 Breakfast","🧹 Cleaning","🔨 DIY","🎹 Music"],"correct":0,"hint":"Butter on toast"},{"prompt":"Electronic beep of the microwave.","options":["🍱 Microwave","📺 TV","📱 Phone","🚪 Door"],"correct":0,"hint":"Heating food"},{"prompt":"Jingling of keys before leaving.","options":["🔑 Leaving","🛌 Sleeping","🍳 Cooking","📖 Reading"],"correct":0,"hint":"Keys in hand"},{"prompt":"The sound of a kettle boiling water.","options":["☕ Breakfast","🚿 Shower","🔊 Music","🍵 Tea time"],"correct":3,"hint":"Hot water for tea"},{"prompt":"The rustling of cereal being poured into a bowl.","options":["🍞 Breakfast","🔪 Cooking","📚 Reading","🚗 Travel"],"correct":0,"hint":"Cereal in the morning"},{"prompt":"The sound of a blender mixing a smoothie.","options":["🥤 Breakfast","🧹 Cleaning","📺 Watching TV","🚿 Shower"],"correct":0,"hint":"Fruits being mixed"},{"prompt":"The clattering of dishes being set on a table.","options":["🚗 Travel","🍽️ Breakfast","🎵 Music","👔 Getting dressed"],"correct":1,"hint":"Setting the table"},{"prompt":"The sound of a coffee machine brewing.","options":["☕ Coffee time","🚿 Shower","📖 Reading","🚗 Travel"],"correct":0,"hint":"Morning coffee"},{"prompt":"The chirping of birds outside the window.","options":["🌅 Morning","🌙 Night","🏙️ City","☁️ Cloudy"],"correct":0,"hint":"Nature sounds"},{"prompt":"The sound of a newspaper being flipped.","options":["📖 Reading","📺 Watching TV","🚗 Travel","🍽️ Breakfast"],"correct":0,"hint":"Morning news"},{"prompt":"The sound of a toast popping up from the toaster.","options":["🍞 Breakfast","🎵 Music","🚿 Shower","🧹 Cleaning"],"correct":0,"hint":"Toast in the morning"},{"prompt":"The sound of a door opening and closing.","options":["🚗 Travel","📖 Reading","👔 Getting dressed","🍽️ Breakfast"],"correct":0,"hint":"Leaving home"},{"prompt":"The sound of a dog barking for a walk.","options":["🚗 Travel","🐕 Walking dog","🍽️ Breakfast","📖 Reading"],"correct":1,"hint":"Pet needs attention"},{"prompt":"The sound of a hairdryer in the bathroom.","options":["🚿 Shower","💇‍♀️ Getting ready","🍽️ Breakfast","📖 Reading"],"correct":1,"hint":"Drying hair"},{"prompt":"The sound of shoes being laced up.","options":["👔 Getting dressed","🚗 Travel","🍽️ Breakfast","📚 Studying"],"correct":0,"hint":"Preparing to leave"},{"prompt":"The sound of someone brushing their teeth.","options":["🚿 Shower","🪥 Morning routine","📖 Reading","🍽️ Breakfast"],"correct":1,"hint":"Hygiene practice"},{"prompt":"The sound of a clock ticking.","options":["🌅 Morning","🌙 Night","🏙️ City","☁️ Cloudy"],"correct":0,"hint":"Time passing"},{"prompt":"The sound of a car engine starting.","options":["🚗 Travel","🍽️ Breakfast","📖 Reading","🛒 Shopping"],"correct":0,"hint":"Ready to go"}]}', 17),
('en', 'B1', 'listening', 'The Secret Garden', 'Soft sounds of a sanctuary', '{"type":"listen_and_choose","instructions":"Identify the delicate sound.","exercises":[{"prompt":"Splashing of a small fountain.","options":["⛲ Fountain","🚿 Shower","🌧️ Rain","🍵 Tea"],"correct":0,"hint":"Courtyard water"},{"prompt":"Buzzing of a bumblebee.","options":["🐝 Bee","🚁 Drone","🏎️ Car","📻 Radio"],"correct":0,"hint":"Insect in garden"},{"prompt":"Rhythmic creak of a wooden gate.","options":["🚪 Gate","🪑 Chair","👣 Steps","🔨 Hammer"],"correct":0,"hint":"Opening gate"},{"prompt":"Distant tolling of a church bell.","options":["🔔 Bell","📱 Phone","⏰ Alarm","📢 Siren"],"correct":0,"hint":"Church sound"},{"prompt":"Soft flutter of butterfly wings.","options":["🦋 Butterfly","🦅 Eagle","✈️ Plane","🚁 Helicopter"],"correct":0,"hint":"Small wings"},{"prompt":"Gentle rustling of leaves in the wind.","options":["🍂 Leaves","🔔 Bell","🌊 Ocean","🎶 Music"],"correct":0,"hint":"Nature''s whisper"},{"prompt":"Soft chirping of crickets at night.","options":["🦗 Cricket","🐦 Bird","🌙 Moon","💤 Sleep"],"correct":0,"hint":"Nighttime melody"},{"prompt":"Distant echo of thunder.","options":["⚡ Lightning","🌩️ Thunder","🕊️ Dove","🚦 Traffic"],"correct":1,"hint":"Stormy sound"},{"prompt":"Quiet tapping of rain on a window.","options":["🌧️ Rain","📦 Box","🔑 Key","🚪 Door"],"correct":0,"hint":"Indoor sound during a storm"},{"prompt":"Soft purring of a cat.","options":["🐱 Cat","🐕 Dog","🐦 Bird","🐍 Snake"],"correct":0,"hint":"Happy feline"},{"prompt":"Crackling of a fire.","options":["🔥 Fire","🚨 Alarm","💡 Light","🎤 Microphone"],"correct":0,"hint":"Cozy warmth"},{"prompt":"Whispering of a gentle breeze.","options":["🍃 Breeze","📯 Horn","🎻 Violin","🎵 Note"],"correct":0,"hint":"Soft air movement"},{"prompt":"Distant call of a loon on a lake.","options":["🦢 Swan","🦩 Flamingo","🦉 Owl","🦆 Loon"],"correct":3,"hint":"Water bird sound"},{"prompt":"Faint dripping of water from a faucet.","options":["💧 Water","🔔 Bell","🎤 Microphone","🪕 Banjo"],"correct":0,"hint":"Leaky tap"},{"prompt":"Soft cooing of a dove.","options":["🕊️ Dove","🐦 Bird","🐸 Frog","🐿️ Squirrel"],"correct":0,"hint":"Peaceful bird"},{"prompt":"Rustling of paper pages in a book.","options":["📚 Book","📖 Magazine","📰 Newspaper","📜 Scroll"],"correct":0,"hint":"Reading sound"},{"prompt":"Murmuring of a small stream.","options":["💦 Stream","🚶‍♂️ Walking","📯 Horn","📻 Radio"],"correct":0,"hint":"Water flowing"},{"prompt":"Humming of a refrigerator.","options":["❄️ Fridge","🔌 Plug","🛋️ Couch","📺 TV"],"correct":0,"hint":"Kitchen appliance"},{"prompt":"Subtle clicking of a computer mouse.","options":["🖱️ Mouse","📱 Phone","📞 Phone","🖥️ Computer"],"correct":0,"hint":"Working at a desk"},{"prompt":"Faint sound of a distant train whistle.","options":["🚂 Train","🚗 Car","🚌 Bus","🚉 Station"],"correct":0,"hint":"Travel sound"}]}', 18),
('en', 'B1', 'listening', 'Stormy Night', 'Intense weather sounds', '{"type":"listen_and_choose","instructions":"Identify the storm element.","exercises":[{"prompt":"Rolling rumble of thunder.","options":["🌩️ Thunder","🚜 Tractor","🚂 Train","🥁 Drums"],"correct":0,"hint":"Rumble in sky"},{"prompt":"Rhythmic drum of heavy rain.","options":["🌧️ Rain","👏 Applause","🍿 Popcorn","🔨 Hammer"],"correct":0,"hint":"Rain on roof"},{"prompt":"Sudden crack of lightning.","options":["⚡ Lightning","💥 Explosion","🔫 Gunshot","🔨 Wood"],"correct":0,"hint":"Electric crack"},{"prompt":"Whistling wind through the eaves.","options":["🌬️ Wind","🫖 Teakettle","🚂 Train","🐦 Bird"],"correct":0,"hint":"Air in eaves"},{"prompt":"Splash of a car through a puddle.","options":["🚗 Puddle","🚿 Shower","🌊 Ocean","☕ Drink"],"correct":0,"hint":"Road splash"},{"prompt":"Whistling wind through the trees.","options":["🌬️ Wind","🚗 Car","🐦 Bird","🎵 Music"],"correct":0,"hint":"Air movement sound"},{"prompt":"Pounding waves against the shore.","options":["🌊 Waves","🐋 Whale","🎣 Fishing","🚢 Ship"],"correct":0,"hint":"Ocean noise"},{"prompt":"Chilling howl of a blizzard.","options":["❄️ Blizzard","🐺 Wolf","🎻 Violin","🥶 Ice"],"correct":0,"hint":"Cold wind sound"},{"prompt":"Gentle patter of sleet on the window.","options":["🌨️ Sleet","📦 Box","🎹 Piano","🚪 Door"],"correct":0,"hint":"Winter precipitation"},{"prompt":"Deep rumble of a distant storm.","options":["🌩️ Thunder","🚂 Train","🎤 Microphone","🔔 Bell"],"correct":0,"hint":"Low sound from afar"},{"prompt":"Crackling of frost underfoot.","options":["❄️ Frost","👣 Footsteps","🎁 Gift","🍂 Leaves"],"correct":0,"hint":"Sound of ice"},{"prompt":"Rushing sound of a flash flood.","options":["🌊 Flood","⛺ Tent","🏃‍♂️ Running","🎉 Party"],"correct":0,"hint":"Water moving quickly"},{"prompt":"Hissing sound of falling hail.","options":["🌨️ Hail","🦇 Bat","🌪️ Tornado","🔊 Speaker"],"correct":0,"hint":"Ice pellets falling"},{"prompt":"Roaring sound of a hurricane.","options":["🌀 Hurricane","🚁 Helicopter","🎤 Speech","🚦 Traffic"],"correct":0,"hint":"Powerful wind noise"},{"prompt":"Rustling leaves during a storm.","options":["🍃 Leaves","🔦 Flashlight","📖 Book","🎈 Balloon"],"correct":0,"hint":"Nature''s sound"},{"prompt":"Distant echo of thunderclaps.","options":["🌩️ Thunder","🔊 Loudspeaker","🚗 Engine","📯 Horn"],"correct":0,"hint":"Sound from the sky"},{"prompt":"Thudding sound of heavy snow falling.","options":["❄️ Snow","🚶‍♀️ Walking","🎈 Balloon","📅 Calendar"],"correct":0,"hint":"Soft winter sound"},{"prompt":"Loud crack of thunder overhead.","options":["🌩️ Thunder","🔨 Hammer","🎸 Guitar","📌 Pin"],"correct":0,"hint":"Loud noise during storm"},{"prompt":"Faint sound of drizzling rain.","options":["🌧️ Rain","📚 Books","💡 Light","🏡 House"],"correct":0,"hint":"Light rain sound"},{"prompt":"Sharp crack of a thunderclap.","options":["⚡ Lightning","🔔 Bell","⌨️ Keyboard","📦 Box"],"correct":0,"hint":"Sudden noise in the sky"}]}', 19),
('en', 'B1', 'listening', 'The Workshop', 'Manual labor sounds', '{"type":"listen_and_choose","instructions":"Which tool is described?","exercises":[{"prompt":"Shrill whine of a circular saw.","options":["🪚 Saw","🔨 Hammer","🪛 Tool","📏 Ruler"],"correct":0,"hint":"Sawing wood"},{"prompt":"Thud of a blacksmith''s hammer.","options":["🔨 Blacksmith","🪓 Chopping","🥁 Drum","👟 Running"],"correct":0,"hint":"Iron work"},{"prompt":"Scratching of sandpaper.","options":["🪵 Sandpaper","🧹 Broom","🖊️ Pen","🐈 Cat"],"correct":0,"hint":"Smoothing wood"},{"prompt":"Hiss of a steam valve.","options":["🏭 Factory","🐍 Snake","🎈 Balloon","🚿 Shower"],"correct":0,"hint":"Steam release"},{"prompt":"Metallic clinking of tools.","options":["🧰 Tools","🍽️ Cutlery","💰 Coins","🔑 Keys"],"correct":0,"hint":"Organizing box"},{"prompt":"Buzzing sound of a drill.","options":["🔩 Screwdriver","🛠️ Drill","🪓 Axe","🔨 Hammer"],"correct":1,"hint":"Making holes"},{"prompt":"Clatter of a toolbox being opened.","options":["🔧 Wrench","🧰 Toolbox","🪛 Screwdriver","📐 Triangle"],"correct":1,"hint":"Getting tools ready"},{"prompt":"Pounding sound of a mallet on wood.","options":["🔨 Hammer","🪓 Chisel","🪄 Mallet","📏 Ruler"],"correct":2,"hint":"Softening impact"},{"prompt":"Creaking noise of a clamp tightening.","options":["🪚 Saw","🧰 Toolbox","🗜️ Clamp","🪛 Screwdriver"],"correct":2,"hint":"Holding pieces together"},{"prompt":"Rippling sound of fabric being cut.","options":["✂️ Scissors","🖊️ Pen","🔨 Hammer","📏 Ruler"],"correct":0,"hint":"Cutting material"},{"prompt":"Whirring sound of a router.","options":["🪚 Saw","🔩 Screw","🪛 Drill","🔧 Router"],"correct":3,"hint":"Shaping edges"},{"prompt":"Clicking sound of a measuring tape retracting.","options":["📏 Ruler","📐 Protractor","📏 Measuring tape","🖊️ Marker"],"correct":2,"hint":"Measuring lengths"},{"prompt":"Grinding sound of a sander.","options":["🪚 Saw","🔨 Hammer","🪵 Sander","🧹 Broom"],"correct":2,"hint":"Smoothing surfaces"},{"prompt":"Chirping sound of a nail gun.","options":["🔨 Hammer","🧰 Toolbox","🔫 Nail gun","🪛 Screwdriver"],"correct":2,"hint":"Fastening quickly"},{"prompt":"Scraping sound of a paint scraper.","options":["🖌️ Brush","🪛 Scraper","🔨 Hammer","📏 Ruler"],"correct":1,"hint":"Removing paint"},{"prompt":"Whistling sound of a steam iron.","options":["👕 Iron","🪡 Needle","🧵 Thread","📏 Ruler"],"correct":0,"hint":"Removing wrinkles"},{"prompt":"Clicking sound of a level being set.","options":["📏 Level","🔨 Hammer","🧰 Toolbox","🪚 Saw"],"correct":0,"hint":"Checking flatness"},{"prompt":"Clanging sound of a metal file.","options":["🪛 Screwdriver","🧰 Toolbox","🔪 File","🔨 Hammer"],"correct":2,"hint":"Sharpening edges"},{"prompt":"Droning sound of a generator.","options":["🔌 Generator","🧰 Toolbox","🔧 Wrench","🪚 Saw"],"correct":0,"hint":"Providing power"},{"prompt":"Rustling sound of a plastic drop sheet.","options":["📏 Ruler","🧰 Toolbox","🪚 Saw","🧻 Drop sheet"],"correct":3,"hint":"Protecting surfaces"}]}', 20);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'B1', 'speaking', 'Describing Art', 'Art vocabulary practice', '{"type":"speak_and_compare","instructions":"Repeat the art description.","exercises":[{"prompt":"The landscape is breathtaking.","expected":"the landscape is breathtaking","hint":"Beautiful view"},{"prompt":"The artist used oil paints.","expected":"the artist used oil paints","hint":"Medium type"},{"prompt":"I love the abstract style.","expected":"i love the abstract style","hint":"Non-realistic"},{"prompt":"It captures a moment in time.","expected":"it captures a moment in time","hint":"Time capture"},{"prompt":"The colors are very vibrant.","expected":"the colors are very vibrant","hint":"Bright colors"},{"prompt":"The colors are vibrant and lively.","expected":"the colors are vibrant and lively","hint":"Bright hues"},{"prompt":"The sculpture is made of marble.","expected":"the sculpture is made of marble","hint":"Material used"},{"prompt":"The painting evokes strong emotions.","expected":"the painting evokes strong emotions","hint":"Emotional response"},{"prompt":"The composition is well-balanced.","expected":"the composition is well-balanced","hint":"Harmony in art"},{"prompt":"The portrait captures the subject''s essence.","expected":"the portrait captures the subject''s essence","hint":"Character portrayal"},{"prompt":"The brushwork is intricate and detailed.","expected":"the brushwork is intricate and detailed","hint":"Technique used"},{"prompt":"This piece is inspired by nature.","expected":"this piece is inspired by nature","hint":"Natural elements"},{"prompt":"The artist''s style is unique and recognizable.","expected":"the artist''s style is unique and recognizable","hint":"Signature look"},{"prompt":"The use of light creates depth.","expected":"the use of light creates depth","hint":"Lighting effect"},{"prompt":"The mural covers an entire wall.","expected":"the mural covers an entire wall","hint":"Large artwork"},{"prompt":"The artwork tells a story.","expected":"the artwork tells a story","hint":"Narrative aspect"},{"prompt":"The textures are rich and varied.","expected":"the textures are rich and varied","hint":"Surface quality"},{"prompt":"The colors blend seamlessly together.","expected":"the colors blend seamlessly together","hint":"Smooth transitions"},{"prompt":"The exhibition features contemporary artists.","expected":"the exhibition features contemporary artists","hint":"Modern art"},{"prompt":"The theme revolves around social issues.","expected":"the theme revolves around social issues","hint":"Relevant topics"}]}', 6),
('en', 'B1', 'speaking', 'Travel Planning', 'Booking a vacation', '{"type":"speak_and_compare","instructions":"Repeat the travel agent phrases.","exercises":[{"prompt":"I would like to book a flight.","expected":"i would like to book a flight","hint":"Booking action"},{"prompt":"Is there a direct flight available?","expected":"is there a direct flight available","hint":"No stops"},{"prompt":"I prefer an aisle seat, please.","expected":"i prefer an aisle seat please","hint":"Seat choice"},{"prompt":"Can I check my luggage here?","expected":"can i check my luggage here","hint":"Bags"},{"prompt":"What is the boarding time?","expected":"what is the boarding time","hint":"Time to board"},{"prompt":"What is the baggage allowance for my flight?","expected":"what is the baggage allowance for my flight","hint":"Luggage limit"},{"prompt":"Can you recommend a hotel nearby?","expected":"can you recommend a hotel nearby","hint":"Accommodation suggestion"},{"prompt":"I need to change my reservation.","expected":"i need to change my reservation","hint":"Modification request"},{"prompt":"What time does the flight depart?","expected":"what time does the flight depart","hint":"Departure inquiry"},{"prompt":"Do you have any special offers?","expected":"do you have any special offers","hint":"Discount inquiry"},{"prompt":"I would like to cancel my booking.","expected":"i would like to cancel my booking","hint":"Cancellation action"},{"prompt":"Is there a shuttle service to the airport?","expected":"is there a shuttle service to the airport","hint":"Transport option"},{"prompt":"What is the total cost of the trip?","expected":"what is the total cost of the trip","hint":"Price inquiry"},{"prompt":"Can I have a window seat instead?","expected":"can i have a window seat instead","hint":"Seat preference change"},{"prompt":"Are meals included in the flight?","expected":"are meals included in the flight","hint":"In-flight service query"},{"prompt":"What is the earliest flight tomorrow?","expected":"what is the earliest flight tomorrow","hint":"Earliest option"},{"prompt":"I need assistance with my luggage.","expected":"i need assistance with my luggage","hint":"Help request"},{"prompt":"Can I upgrade my seat?","expected":"can i upgrade my seat","hint":"Seat upgrade inquiry"},{"prompt":"What is the return policy for tickets?","expected":"what is the return policy for tickets","hint":"Refund information"},{"prompt":"Are there any layovers on this route?","expected":"are there any layovers on this route","hint":"Stopover inquiry"}]}', 7),
('en', 'B1', 'speaking', 'Job Interview', 'Common interview phrases', '{"type":"speak_and_compare","instructions":"Practice your interview responses.","exercises":[{"prompt":"I have five years of experience.","expected":"i have five years of experience","hint":"Work history"},{"prompt":"I am a hard-working person.","expected":"i am a hard working person","hint":"Work ethic"},{"prompt":"I enjoy working in a team.","expected":"i enjoy working in a team","hint":"Teamwork"},{"prompt":"I am looking for new challenges.","expected":"i am looking for new challenges","hint":"Career goals"},{"prompt":"Thank you for the opportunity.","expected":"thank you for the opportunity","hint":"Polite closing"},{"prompt":"I am adaptable to new situations.","expected":"i am adaptable to new situations","hint":"Flexibility"},{"prompt":"I have strong communication skills.","expected":"i have strong communication skills","hint":"Communication"},{"prompt":"I am eager to learn new things.","expected":"i am eager to learn new things","hint":"Learning attitude"},{"prompt":"I can handle stressful situations well.","expected":"i can handle stressful situations well","hint":"Stress management"},{"prompt":"I am detail-oriented.","expected":"i am detail oriented","hint":"Attention to detail"},{"prompt":"I have leadership experience.","expected":"i have leadership experience","hint":"Leadership"},{"prompt":"I can work independently.","expected":"i can work independently","hint":"Self-motivation"},{"prompt":"I am passionate about my work.","expected":"i am passionate about my work","hint":"Passion"},{"prompt":"I appreciate constructive feedback.","expected":"i appreciate constructive feedback","hint":"Receptiveness"},{"prompt":"I have a positive attitude.","expected":"i have a positive attitude","hint":"Positivity"},{"prompt":"I am willing to take on new challenges.","expected":"i am willing to take on new challenges","hint":"Challenge acceptance"},{"prompt":"I am organized and manage my time well.","expected":"i am organized and manage my time well","hint":"Time management"},{"prompt":"I can think critically and solve problems.","expected":"i can think critically and solve problems","hint":"Critical thinking"},{"prompt":"I have experience with project management.","expected":"i have experience with project management","hint":"Project management"},{"prompt":"I enjoy networking and building relationships.","expected":"i enjoy networking and building relationships","hint":"Networking"}]}', 8),
('en', 'B1', 'speaking', 'Making a Complaint', 'Polite ways to complain', '{"type":"speak_and_compare","instructions":"Practice being polite but firm.","exercises":[{"prompt":"Excuse me, there is a mistake.","expected":"excuse me there is a mistake","hint":"Polite opening"},{"prompt":"The service was quite slow today.","expected":"the service was quite slow today","hint":"Describing issue"},{"prompt":"I am not happy with this meal.","expected":"i am not happy with this meal","hint":"Direct complaint"},{"prompt":"Could I speak to the manager?","expected":"could i speak to the manager","hint":"Escalation"},{"prompt":"Thank you for fixing the issue.","expected":"thank you for fixing the issue","hint":"Resolution"},{"prompt":"I believe there was an error in my bill.","expected":"i believe there was an error in my bill","hint":"Addressing a billing issue"},{"prompt":"Could you please check on my order?","expected":"could you please check on my order","hint":"Polite request for information"},{"prompt":"I''m afraid the room is not clean.","expected":"i''m afraid the room is not clean","hint":"Expressing disappointment"},{"prompt":"This is not what I ordered.","expected":"this is not what i ordered","hint":"Clarifying a mistake"},{"prompt":"I would appreciate a faster response.","expected":"i would appreciate a faster response","hint":"Requesting urgency"},{"prompt":"Unfortunately, the food is cold.","expected":"unfortunately the food is cold","hint":"Stating a problem"},{"prompt":"I need to speak to the manager.","expected":"i need to speak to the manager","hint":"Requesting escalation"},{"prompt":"I think there was a misunderstanding.","expected":"i think there was a misunderstanding","hint":"Pointing out confusion"},{"prompt":"This item is defective.","expected":"this item is defective","hint":"Identifying a product issue"},{"prompt":"Could you help me with this issue?","expected":"could you help me with this issue","hint":"Seeking assistance"},{"prompt":"I would like a refund, please.","expected":"i would like a refund please","hint":"Requesting a refund"},{"prompt":"The music is too loud for my liking.","expected":"the music is too loud for my liking","hint":"Giving feedback on environment"},{"prompt":"I wasn''t informed about the delay.","expected":"i wasn''t informed about the delay","hint":"Expressing lack of communication"},{"prompt":"The product did not meet my expectations.","expected":"the product did not meet my expectations","hint":"Expressing dissatisfaction"},{"prompt":"I would like to change my reservation.","expected":"i would like to change my reservation","hint":"Requesting a modification"}]}', 9),
('en', 'B1', 'speaking', 'Giving Advice', 'Suggesting solutions', '{"type":"speak_and_compare","instructions":"Practice modal verbs for advice.","exercises":[{"prompt":"You should try to relax more.","expected":"you should try to relax more","hint":"Recommendation"},{"prompt":"If I were you, I would go.","expected":"if i were you i would go","hint":"Conditional advice"},{"prompt":"Why don''t you call your friend?","expected":"why dont you call your friend","hint":"Suggestion"},{"prompt":"It might be a good idea.","expected":"it might be a good idea","hint":"Softening advice"},{"prompt":"You ought to see a doctor.","expected":"you ought to see a doctor","hint":"Strong advice"},{"prompt":"You might want to consider a different approach.","expected":"you might want to consider a different approach","hint":"Possibility"},{"prompt":"You could ask for help if you''re struggling.","expected":"you could ask for help if you are struggling","hint":"Alternative suggestion"},{"prompt":"You ought to take a break now and then.","expected":"you ought to take a break now and then","hint":"Obligation"},{"prompt":"Why not try a new hobby?","expected":"why not try a new hobby","hint":"Encouragement"},{"prompt":"You should definitely visit that museum.","expected":"you should definitely visit that museum","hint":"Strong recommendation"},{"prompt":"If I were in your shoes, I would think twice.","expected":"if i were in your shoes i would think twice","hint":"Hypothetical advice"},{"prompt":"You can always reach out to a mentor.","expected":"you can always reach out to a mentor","hint":"Possibility"},{"prompt":"You may want to check your schedule first.","expected":"you may want to check your schedule first","hint":"Suggestion"},{"prompt":"It would be wise to save some money.","expected":"it would be wise to save some money","hint":"Prudent advice"},{"prompt":"You should think about your long-term goals.","expected":"you should think about your long term goals","hint":"Recommendation"},{"prompt":"Why don''t you take that opportunity?","expected":"why dont you take that opportunity","hint":"Encouragement"},{"prompt":"You ought to apologize if you were wrong.","expected":"you ought to apologize if you were wrong","hint":"Moral obligation"},{"prompt":"You could try reading more books.","expected":"you could try reading more books","hint":"Suggestion"},{"prompt":"It might be beneficial to network more.","expected":"it might be beneficial to network more","hint":"Advice for improvement"},{"prompt":"If I were you, I would take the job offer.","expected":"if i were you i would take the job offer","hint":"Conditional advice"}]}', 10),
('en', 'B1', 'speaking', 'Tech Talk', 'Discussing gadgets', '{"type":"speak_and_compare","instructions":"Talk about modern technology.","exercises":[{"prompt":"My phone has a great camera.","expected":"my phone has a great camera","hint":"Feature"},{"prompt":"I use this app every day.","expected":"i use this app every day","hint":"Usage"},{"prompt":"The battery life is excellent.","expected":"the battery life is excellent","hint":"Performance"},{"prompt":"Is the software updated?","expected":"is the software updated","hint":"Maintenance"},{"prompt":"I cannot live without Wi-Fi.","expected":"i cannot live without wi fi","hint":"Necessity"},{"prompt":"I can connect to Wi-Fi easily.","expected":"i can connect to wifi easily","hint":"Connectivity"},{"prompt":"This tablet is lightweight and portable.","expected":"this tablet is lightweight and portable","hint":"Design"},{"prompt":"Voice assistants help me manage my tasks.","expected":"voice assistants help me manage my tasks","hint":"Functionality"},{"prompt":"I enjoy streaming movies on my smart TV.","expected":"i enjoy streaming movies on my smart tv","hint":"Entertainment"},{"prompt":"The touchscreen is very responsive.","expected":"the touchscreen is very responsive","hint":"Usability"},{"prompt":"My smartwatch tracks my fitness activities.","expected":"my smartwatch tracks my fitness activities","hint":"Health"},{"prompt":"I often use cloud storage for my files.","expected":"i often use cloud storage for my files","hint":"Storage"},{"prompt":"This gaming console has impressive graphics.","expected":"this gaming console has impressive graphics","hint":"Performance"},{"prompt":"Social media keeps me connected with friends.","expected":"social media keeps me connected with friends","hint":"Communication"},{"prompt":"My laptop has a fast processor.","expected":"my laptop has a fast processor","hint":"Performance"},{"prompt":"I love using virtual reality for gaming.","expected":"i love using virtual reality for gaming","hint":"Experience"},{"prompt":"Online shopping is so convenient.","expected":"online shopping is so convenient","hint":"Convenience"},{"prompt":"I rely on GPS for navigation.","expected":"i rely on gps for navigation","hint":"Navigation"},{"prompt":"I appreciate the security features of my phone.","expected":"i appreciate the security features of my phone","hint":"Security"},{"prompt":"I can control my home devices remotely.","expected":"i can control my home devices remotely","hint":"Smart Home"}]}', 11),
('en', 'B1', 'speaking', 'Sharing News', 'Talking about events', '{"type":"speak_and_compare","instructions":"Practice conversational news.","exercises":[{"prompt":"Did you hear the latest news?","expected":"did you hear the latest news","hint":"Opening"},{"prompt":"It was all over the internet.","expected":"it was all over the internet","hint":"Source"},{"prompt":"I was so surprised by it.","expected":"i was so surprised by it","hint":"Reaction"},{"prompt":"Everyone is talking about it.","expected":"everyone is talking about it","hint":"Popularity"},{"prompt":"I hope things get better soon.","expected":"i hope things get better soon","hint":"Closing"},{"prompt":"Have you seen the breaking news?","expected":"have you seen the breaking news","hint":"Opening"},{"prompt":"It caught everyone off guard.","expected":"it caught everyone off guard","hint":"Reaction"},{"prompt":"The news spread like wildfire.","expected":"the news spread like wildfire","hint":"Source"},{"prompt":"What do you think about it?","expected":"what do you think about it","hint":"Question"},{"prompt":"I couldn''t believe my eyes.","expected":"i couldn''t believe my eyes","hint":"Reaction"},{"prompt":"They reported it this morning.","expected":"they reported it this morning","hint":"Source"},{"prompt":"It really made me think.","expected":"it really made me think","hint":"Reaction"},{"prompt":"Did you read the article?","expected":"did you read the article","hint":"Opening"},{"prompt":"It was trending for hours.","expected":"it was trending for hours","hint":"Source"},{"prompt":"I felt a mix of emotions.","expected":"i felt a mix of emotions","hint":"Reaction"},{"prompt":"What was your first reaction?","expected":"what was your first reaction","hint":"Question"},{"prompt":"Everyone was talking about it.","expected":"everyone was talking about it","hint":"Source"},{"prompt":"I was really moved by it.","expected":"i was really moved by it","hint":"Reaction"},{"prompt":"Did you catch the latest update?","expected":"did you catch the latest update","hint":"Opening"},{"prompt":"The reactions were mixed.","expected":"the reactions were mixed","hint":"Source"},{"prompt":"It left me speechless.","expected":"it left me speechless","hint":"Reaction"}]}', 12),
('en', 'B1', 'speaking', 'A Great Story', 'Narrative practice', '{"type":"speak_and_compare","instructions":"Tell a short story fragment.","exercises":[{"prompt":"Once upon a time, there was.","expected":"once upon a time there was","hint":"Starting"},{"prompt":"Suddenly, the lights went out.","expected":"suddenly the lights went out","hint":"Action"},{"prompt":"We didn''t know what to do.","expected":"we didnt know what to do","hint":"Conflict"},{"prompt":"Finally, the sun came up.","expected":"finally the sun came up","hint":"Resolution"},{"prompt":"It was an amazing adventure.","expected":"it was an amazing adventure","hint":"Summary"},{"prompt":"In a distant land, a dragon slept.","expected":"in a distant land a dragon slept","hint":"Setting"},{"prompt":"Suddenly, a loud roar echoed.","expected":"suddenly a loud roar echoed","hint":"Action"},{"prompt":"The villagers were terrified.","expected":"the villagers were terrified","hint":"Reaction"},{"prompt":"A brave knight decided to help.","expected":"a brave knight decided to help","hint":"Decision"},{"prompt":"He gathered his armor and sword.","expected":"he gathered his armor and sword","hint":"Preparation"},{"prompt":"As he approached the cave, he trembled.","expected":"as he approached the cave he trembled","hint":"Emotion"},{"prompt":"Inside, he found glittering treasures.","expected":"inside he found glittering treasures","hint":"Discovery"},{"prompt":"But the dragon was awake.","expected":"but the dragon was awake","hint":"Twist"},{"prompt":"They stared at each other in shock.","expected":"they stared at each other in shock","hint":"Moment"},{"prompt":"The knight took a deep breath.","expected":"the knight took a deep breath","hint":"Preparation"},{"prompt":"With a loud shout, he charged forward.","expected":"with a loud shout he charged forward","hint":"Action"},{"prompt":"The dragon breathed fire.","expected":"the dragon breathed fire","hint":"Conflict"},{"prompt":"The knight dodged just in time.","expected":"the knight dodged just in time","hint":"Survival"},{"prompt":"He swung his sword with all his might.","expected":"he swung his sword with all his might","hint":"Climax"},{"prompt":"And in that moment, everything changed.","expected":"and in that moment everything changed","hint":"Resolution"}]}', 13),
('en', 'B1', 'speaking', 'Opinions on Food', 'Discussing flavors', '{"type":"speak_and_compare","instructions":"Express your culinary tastes.","exercises":[{"prompt":"This dish is a bit too spicy.","expected":"this dish is a bit too spicy","hint":"Taste"},{"prompt":"The sauce is rich and creamy.","expected":"the sauce is rich and creamy","hint":"Texture"},{"prompt":"I prefer sweet to savory.","expected":"i prefer sweet to savory","hint":"Preference"},{"prompt":"It smells absolutely delicious.","expected":"it smells absolutely delicious","hint":"Aroma"},{"prompt":"I would definitely order this again.","expected":"i would definitely order this again","hint":"Review"},{"prompt":"This dessert is too sweet for my taste.","expected":"this dessert is too sweet for my taste","hint":"Taste"},{"prompt":"The pasta is cooked al dente.","expected":"the pasta is cooked al dente","hint":"Texture"},{"prompt":"I enjoy bold flavors in my meals.","expected":"i enjoy bold flavors in my meals","hint":"Preference"},{"prompt":"The salad is fresh and crunchy.","expected":"the salad is fresh and crunchy","hint":"Texture"},{"prompt":"I dislike overly salty foods.","expected":"i dislike overly salty foods","hint":"Preference"},{"prompt":"The soup is hearty and filling.","expected":"the soup is hearty and filling","hint":"Texture"},{"prompt":"This dish has a delightful aroma.","expected":"this dish has a delightful aroma","hint":"Taste"},{"prompt":"I prefer grilled vegetables over steamed.","expected":"i prefer grilled vegetables over steamed","hint":"Preference"},{"prompt":"The cake is moist and fluffy.","expected":"the cake is moist and fluffy","hint":"Texture"},{"prompt":"The curry has a complex flavor profile.","expected":"the curry has a complex flavor profile","hint":"Taste"},{"prompt":"I love tangy dressings on my salads.","expected":"i love tangy dressings on my salads","hint":"Preference"},{"prompt":"The chocolate is rich and velvety.","expected":"the chocolate is rich and velvety","hint":"Texture"},{"prompt":"This dish could use a bit more seasoning.","expected":"this dish could use a bit more seasoning","hint":"Taste"},{"prompt":"I enjoy creamy soups during winter.","expected":"i enjoy creamy soups during winter","hint":"Preference"},{"prompt":"The bread is crusty on the outside.","expected":"the bread is crusty on the outside","hint":"Texture"}]}', 14),
('en', 'B1', 'speaking', 'Socializing', 'Meeting people at a party', '{"type":"speak_and_compare","instructions":"Practice small talk phrases.","exercises":[{"prompt":"So, what do you do for work?","expected":"so what do you do for work","hint":"Question"},{"prompt":"I haven''t seen you here before.","expected":"i havent seen you here before","hint":"Observation"},{"prompt":"This is a wonderful party.","expected":"this is a wonderful party","hint":"Compliment"},{"prompt":"Would you like another drink?","expected":"would you like another drink","hint":"Offering"},{"prompt":"It was nice talking to you.","expected":"it was nice talking to you","hint":"Leaving"},{"prompt":"What do you like to do in your free time?","expected":"what do you like to do in your free time","hint":"Question"},{"prompt":"The weather is lovely today.","expected":"the weather is lovely today","hint":"Observation"},{"prompt":"Have you tried the food here?","expected":"have you tried the food here","hint":"Question"},{"prompt":"I love your outfit!","expected":"i love your outfit","hint":"Compliment"},{"prompt":"How do you know the host?","expected":"how do you know the host","hint":"Question"},{"prompt":"This place has a great atmosphere.","expected":"this place has a great atmosphere","hint":"Observation"},{"prompt":"What kind of music do you enjoy?","expected":"what kind of music do you enjoy","hint":"Question"},{"prompt":"You''re really good at dancing!","expected":"youre really good at dancing","hint":"Compliment"},{"prompt":"Have you been on any trips lately?","expected":"have you been on any trips lately","hint":"Question"},{"prompt":"This drink is delicious.","expected":"this drink is delicious","hint":"Observation"},{"prompt":"What hobbies do you have?","expected":"what hobbies do you have","hint":"Question"},{"prompt":"You have a great sense of humor.","expected":"you have a great sense of humor","hint":"Compliment"},{"prompt":"Do you have any pets?","expected":"do you have any pets","hint":"Question"},{"prompt":"I really enjoyed that conversation.","expected":"i really enjoyed that conversation","hint":"Observation"},{"prompt":"What do you think of this event?","expected":"what do you think of this event","hint":"Question"}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'B1', 'reading', 'The Roman Empire', 'A short history passage', '{"type":"read_and_choose","instructions":"Read and answer the questions.","passage":"The Roman Empire was one of the largest and most powerful empires in history. At its height, it controlled lands all around the Mediterranean Sea. The Romans built incredible roads, bridges, and aqueducts that lasted for centuries. Their language, Latin, influenced many modern languages.","exercises":[{"question":"What did the Romans build?","options":["Roads","Cars","Planes","Trains"],"correct":0},{"question":"Where was the empire centered?","options":["Mediterranean","Atlantic","Pacific","Arctic"],"correct":0},{"question":"What was their language?","options":["Latin","English","French","German"],"correct":0},{"question":"Was the empire small?","options":["No, it was large","Yes","Maybe","Unknown"],"correct":0},{"question":"Did they influence languages?","options":["Yes","No","A bit","Never"],"correct":0},{"question":"What type of government did the Romans have?","options":["Republic","Monarchy","Dictatorship","Oligarchy"],"correct":0},{"question":"What was the primary currency used in ancient Rome?","options":["Denarius","Dollar","Euro","Pound"],"correct":0},{"question":"Who was the first Roman Emperor?","options":["Augustus","Julius Caesar","Nero","Tiberius"],"correct":0},{"question":"What structure is famous for its gladiatorial games?","options":["Colosseum","Pantheon","Aqueduct","Forum"],"correct":0},{"question":"Which river flows through Rome?","options":["Tiber","Nile","Thames","Danube"],"correct":0},{"question":"What was a Roman military unit called?","options":["Legion","Brigade","Battalion","Squad"],"correct":0},{"question":"What famous road connected Rome to the South of Italy?","options":["Appian Way","Silk Road","Route 66","Pan-American Highway"],"correct":0},{"question":"What was the primary role of the Senate in Rome?","options":["Advisory","Judicial","Military","Religious"],"correct":0},{"question":"What was the dominant religion in ancient Rome before Christianity?","options":["Polytheism","Monotheism","Atheism","Agnosticism"],"correct":0},{"question":"What structure did Romans build to transport water?","options":["Aqueducts","Canals","Pipelines","Dams"],"correct":0},{"question":"Who was a famous Roman general known for his campaigns in Gaul?","options":["Julius Caesar","Pompey","Hannibal","Augustus"],"correct":0},{"question":"What was the name of the Roman peace period?","options":["Pax Romana","Pax Britannica","Pax Americana","Pax Sinica"],"correct":0},{"question":"Which famous Roman orator is known for his speeches?","options":["Cicero","Virgil","Seneca","Ovid"],"correct":0},{"question":"What form of architecture is the Roman arch associated with?","options":["Vaulting","Gothic","Baroque","Renaissance"],"correct":0},{"question":"What was the primary purpose of Roman baths?","options":["Hygiene","Recreation","Religious rituals","Education"],"correct":0}]}', 6),
('en', 'B1', 'reading', 'Space Exploration', 'Understanding the universe', '{"type":"read_and_choose","instructions":"Read and answer.","passage":"Humans have always been curious about space. In 1969, Apollo 11 successfully landed on the moon. Today, scientists are planning missions to Mars. They use powerful telescopes to see distant galaxies. The international space station is a place where astronauts live and work.","exercises":[{"question":"When did humans land on the moon?","options":["1969","1959","1979","1989"],"correct":0},{"question":"Which planet is next for missions?","options":["Mars","Venus","Jupiter","Saturn"],"correct":0},{"question":"What do scientists use to see?","options":["Telescopes","Microscopes","Glasses","Cameras"],"correct":0},{"question":"Who lives on the space station?","options":["Astronauts","Doctors","Teachers","Drivers"],"correct":0},{"question":"Are humans curious about space?","options":["Yes","No","Sometimes","Rarely"],"correct":0},{"question":"What is the primary gas in Earth''s atmosphere?","options":["Oxygen","Nitrogen","Carbon Dioxide","Hydrogen"],"correct":1},{"question":"Which celestial body is known as the Red Planet?","options":["Mars","Earth","Venus","Jupiter"],"correct":0},{"question":"What is the closest star to Earth?","options":["Proxima Centauri","Sirius","Alpha Centauri","Betelgeuse"],"correct":0},{"question":"What is the largest planet in our solar system?","options":["Saturn","Earth","Jupiter","Neptune"],"correct":2},{"question":"What tool do scientists use to measure temperature?","options":["Barometer","Thermometer","Hygrometer","Anemometer"],"correct":1},{"question":"Which element is represented by the symbol ''H''?","options":["Helium","Hydrogen","Oxygen","Nitrogen"],"correct":1},{"question":"What do you call the force that attracts objects towards each other?","options":["Magnetism","Gravity","Friction","Pressure"],"correct":1},{"question":"Which planet is known for its rings?","options":["Mars","Earth","Saturn","Uranus"],"correct":2},{"question":"What is the process by which plants make their food?","options":["Photosynthesis","Respiration","Digestion","Fermentation"],"correct":0},{"question":"Which device is used to view distant objects in space?","options":["Microscope","Telescope","Camera","Spectrometer"],"correct":1},{"question":"What is the boiling point of water at sea level?","options":["100 degrees Celsius","90 degrees Celsius","80 degrees Celsius","110 degrees Celsius"],"correct":0},{"question":"Which planet is known as the Morning Star?","options":["Mercury","Venus","Mars","Saturn"],"correct":1},{"question":"What do you call the study of living organisms?","options":["Zoology","Botany","Biology","Ecology"],"correct":2},{"question":"Which phenomenon causes day and night?","options":["Revolution","Rotation","Gravity","Magnetism"],"correct":1},{"question":"What is the main source of energy for Earth?","options":["The Moon","The Sun","Wind","Geothermal"],"correct":1}]}', 7),
('en', 'B1', 'reading', 'Famous Scientists', 'Biography fragments', '{"type":"read_and_choose","instructions":"Identify the scientist.","exercises":[{"question":"Who discovered gravity?","options":["Isaac Newton","Albert Einstein","Marie Curie","Darwin"],"correct":0},{"question":"Who worked on radioactivity?","options":["Marie Curie","Newton","Einstein","Tesla"],"correct":0},{"question":"Who developed relativity?","options":["Albert Einstein","Curie","Newton","Bell"],"correct":0},{"question":"Who studied evolution?","options":["Charles Darwin","Mendel","Curie","Newton"],"correct":0},{"question":"Who invented the lightbulb?","options":["Thomas Edison","Tesla","Bell","Ford"],"correct":1},{"question":"Who is known for the laws of motion?","options":["Isaac Newton","Galileo Galilei","Niels Bohr","Charles Darwin"],"correct":0},{"question":"Who is famous for the structure of DNA?","options":["James Watson","Louis Pasteur","Albert Einstein","Marie Curie"],"correct":0},{"question":"Who developed the periodic table?","options":["Dmitri Mendeleev","Albert Einstein","Robert Hooke","Isaac Newton"],"correct":0},{"question":"Who proposed the heliocentric theory?","options":["Nicolaus Copernicus","Galileo Galilei","Isaac Newton","Johannes Kepler"],"correct":0},{"question":"Who is known for his work on electromagnetism?","options":["James Clerk Maxwell","Albert Einstein","Nikola Tesla","Thomas Edison"],"correct":0},{"question":"Who discovered penicillin?","options":["Alexander Fleming","Marie Curie","Louis Pasteur","Gregor Mendel"],"correct":0},{"question":"Who is known for the theory of evolution?","options":["Charles Darwin","Gregor Mendel","Albert Einstein","Louis Pasteur"],"correct":0},{"question":"Who is famous for his work on the atom?","options":["Niels Bohr","Albert Einstein","Isaac Newton","Erwin Schrödinger"],"correct":0},{"question":"Who created the first vaccine?","options":["Edward Jenner","Louis Pasteur","Marie Curie","Charles Darwin"],"correct":0},{"question":"Who is known for his work on genetics?","options":["Gregor Mendel","Charles Darwin","Richard Dawkins","James Watson"],"correct":0},{"question":"Who proposed the laws of planetary motion?","options":["Johannes Kepler","Isaac Newton","Galileo Galilei","Tycho Brahe"],"correct":0},{"question":"Who discovered the electron?","options":["J.J. Thomson","Ernest Rutherford","Niels Bohr","Albert Einstein"],"correct":0},{"question":"Who is known for the uncertainty principle?","options":["Werner Heisenberg","Albert Einstein","Niels Bohr","Erwin Schrödinger"],"correct":0},{"question":"Who is credited with the invention of the telephone?","options":["Alexander Graham Bell","Thomas Edison","Nikola Tesla","Guglielmo Marconi"],"correct":0},{"question":"Who is famous for his work on light and optics?","options":["Isaac Newton","Albert Einstein","Thomas Young","James Clerk Maxwell"],"correct":0}]}', 8),
('en', 'B1', 'reading', 'Movie Review', 'Understanding opinions', '{"type":"read_and_choose","instructions":"Analyze the review.","passage":"The new action movie was exciting but a bit too long. The special effects were amazing, especially the explosions. However, the acting was not very good. Overall, it is worth watching if you like fast-paced films.","exercises":[{"question":"Was the movie exciting?","options":["Yes","No","Boring","Slow"],"correct":0},{"question":"What was amazing?","options":["Effects","Acting","Music","Script"],"correct":0},{"question":"Was the acting good?","options":["No","Yes","Perfect","Great"],"correct":0},{"question":"What was the problem?","options":["Length","Sound","Color","Title"],"correct":0},{"question":"Is it worth watching?","options":["Yes","No","Maybe","Never"],"correct":0},{"question":"Was the plot engaging?","options":["Yes","No","Confusing","Predictable"],"correct":0},{"question":"How was the cinematography?","options":["Stunning","Average","Poor","Mediocre"],"correct":0},{"question":"Was the soundtrack memorable?","options":["Yes","No","Forgettable","Generic"],"correct":0},{"question":"Did the characters feel realistic?","options":["Yes","No","Stereotypical","Unbelievable"],"correct":0},{"question":"How was the pacing of the movie?","options":["Fast","Slow","Just right","Rushed"],"correct":2},{"question":"Was the ending satisfying?","options":["Yes","No","Open-ended","Unclear"],"correct":0},{"question":"Were the visual effects impressive?","options":["Yes","No","Average","Subpar"],"correct":0},{"question":"Did the movie have good humor?","options":["Yes","No","Forced","Missing"],"correct":0},{"question":"Was the dialogue well-written?","options":["Yes","No","Cliché","Awkward"],"correct":0},{"question":"Did the movie keep your attention?","options":["Yes","No","Dull","Distracting"],"correct":0},{"question":"How was the overall production quality?","options":["High","Low","Average","Subpar"],"correct":0},{"question":"Were the themes thought-provoking?","options":["Yes","No","Shallow","Confusing"],"correct":0},{"question":"How was the direction of the movie?","options":["Excellent","Poor","Average","Mediocre"],"correct":0},{"question":"Was the movie worth watching?","options":["Yes","No","Only once","Not at all"],"correct":0},{"question":"Did the movie have a strong message?","options":["Yes","No","Weak","Confusing"],"correct":0}]}', 9),
('en', 'B1', 'reading', 'A Secret Recipe', 'Following instructions', '{"type":"read_and_choose","instructions":"Answer about the recipe.","passage":"To make the perfect pasta, boil water first. Add a pinch of salt. Cook the pasta for eight minutes. Meanwhile, heat the sauce in a small pan. Mix everything together and serve with cheese.","exercises":[{"question":"What do you do first?","options":["Boil water","Add salt","Cook pasta","Heat sauce"],"correct":0},{"question":"How long for pasta?","options":["8 mins","5 mins","10 mins","12 mins"],"correct":0},{"question":"What kind of pan for sauce?","options":["Small","Big","Deep","Frying"],"correct":0},{"question":"What should you add to water?","options":["Salt","Sugar","Oil","Pepper"],"correct":0},{"question":"What is the final step?","options":["Serve with cheese","Add water","Buy pasta","Clean pan"],"correct":0},{"question":"What should you do after boiling water?","options":["Add pasta","Drain water","Turn off the heat","Add oil"],"correct":0},{"question":"What to add to the water for flavor?","options":["Vinegar","Salt","Sugar","Olive oil"],"correct":1},{"question":"How do you test if the pasta is done?","options":["Taste a piece","Look at the color","Check the package time","Feel the texture"],"correct":0},{"question":"What should you do with the pasta after cooking?","options":["Rinse with cold water","Let it sit","Mix with sauce immediately","Add cheese"],"correct":2},{"question":"What type of cheese is often used in pasta dishes?","options":["Cheddar","Parmesan","Mozzarella","Feta"],"correct":1},{"question":"How do you prepare the sauce?","options":["Heat in a microwave","Simmer in a pan","Mix in a bowl","Chill in the fridge"],"correct":1},{"question":"What is a common ingredient in tomato sauce?","options":["Basil","Cinnamon","Nutmeg","Ginger"],"correct":0},{"question":"What should you do if the sauce is too thick?","options":["Add more pasta","Add water","Stir vigorously","Cook longer"],"correct":1},{"question":"What utensil is best for stirring sauce?","options":["Fork","Whisk","Wooden spoon","Spatula"],"correct":2},{"question":"What is a good garnish for pasta?","options":["Chopped parsley","Sliced lemon","Crushed garlic","Chili flakes"],"correct":0},{"question":"What is a common side dish with pasta?","options":["Salad","Rice","Bread","Potatoes"],"correct":0},{"question":"What should you do with leftover pasta?","options":["Throw it away","Store in the fridge","Leave it out","Reheat in the oven"],"correct":1},{"question":"How can you prevent pasta from sticking?","options":["Add more salt","Stir occasionally","Use a larger pot","Rinse before cooking"],"correct":1},{"question":"What can you add to pasta for extra protein?","options":["Chicken","Broccoli","Tomato","Onion"],"correct":0},{"question":"What is the best way to serve pasta?","options":["In a bowl","On a plate","In a pot","Wrapped in foil"],"correct":1}]}', 10),
('en', 'B1', 'reading', 'Electronic Manual', 'Technical reading', '{"type":"read_and_choose","instructions":"Understand the manual.","passage":"Press the power button for three seconds to turn on the device. A blue light will flash. If the light is red, the battery is low. Use the included USB cable to charge. Avoid contact with water.","exercises":[{"question":"How long to press?","options":["3 seconds","1 second","5 seconds","10 seconds"],"correct":0},{"question":"What does blue light mean?","options":["Turning on","Low battery","Error","Charging"],"correct":0},{"question":"What if it is red?","options":["Low battery","Ready","Off","Full"],"correct":0},{"question":"How to charge?","options":["USB cable","Battery","Sun","Wall"],"correct":0},{"question":"Can you get it wet?","options":["No","Yes","Maybe","Unknown"],"correct":0},{"question":"What does a green light indicate?","options":["Charging","Full battery","Error","Turning off"],"correct":1},{"question":"How to reset the device?","options":["Hold the power button","Remove the battery","Press the volume up button","Unplug it"],"correct":0},{"question":"What does a flashing blue light mean?","options":["Connecting","Battery low","Device off","Fully charged"],"correct":0},{"question":"What should you do if it won''t turn on?","options":["Charge it","Press the reset button","Replace the battery","Check the settings"],"correct":0},{"question":"What does the warning sound mean?","options":["Low battery","Device ready","Connection established","Error occurred"],"correct":3},{"question":"What does a solid red light indicate?","options":["Charging","Battery full","Error","Device off"],"correct":2},{"question":"How often should you update the software?","options":["Every month","Once a year","Every week","Whenever prompted"],"correct":3},{"question":"What does a continuous beep sound indicate?","options":["Ready to use","Battery low","Connection success","Error state"],"correct":1},{"question":"What does it mean when the device vibrates?","options":["Incoming call","Battery low","Device off","Syncing"],"correct":0},{"question":"What should you do if the screen freezes?","options":["Restart the device","Charge the battery","Wait for a while","Check the settings"],"correct":0},{"question":"What indicates a successful connection?","options":["Flashing green light","Solid red light","Continuous beep","Device off"],"correct":0},{"question":"What does a yellow light signify?","options":["Error","Low battery","Charging","Device ready"],"correct":1},{"question":"What should you do before cleaning the device?","options":["Turn it off","Disconnect from power","Remove the battery","All of the above"],"correct":3},{"question":"What happens when the battery is fully charged?","options":["Light turns green","Device shuts down","Starts overheating","Beeping sound"],"correct":0},{"question":"What does it mean if the device powers off unexpectedly?","options":["Battery issue","Software update needed","Connection lost","Device is overheating"],"correct":0}]}', 11),
('en', 'B1', 'reading', 'Formal Letter', 'Business communication', '{"type":"read_and_choose","instructions":"Identify the purpose.","passage":"Dear Mr. Jones, I am writing to confirm our meeting on Monday at 10 AM. Please bring the latest report with you. We will discuss the new budget in the conference room. Best regards, Jane Smith.","exercises":[{"question":"Who is the letter to?","options":["Mr. Jones","Jane Smith","Tom","Sarah"],"correct":0},{"question":"What time is the meeting?","options":["10 AM","9 AM","11 AM","2 PM"],"correct":0},{"question":"What should he bring?","options":["Report","Coffee","Laptop","Book"],"correct":0},{"question":"What is the topic?","options":["Budget","Holidays","Weather","Food"],"correct":0},{"question":"Who wrote the letter?","options":["Jane Smith","Mr. Jones","The boss","Secretary"],"correct":0},{"question":"Where is the event taking place?","options":["City Hall","Community Center","Library","Park"],"correct":1},{"question":"What is the main topic of the presentation?","options":["Marketing Strategies","Financial Reports","Team Building","Product Launch"],"correct":3},{"question":"Who will be the guest speaker?","options":["Dr. Emily Clark","Mr. Robert Brown","Ms. Alice Green","Mrs. Sarah White"],"correct":2},{"question":"When is the deadline for submissions?","options":["Friday","Monday","Wednesday","Saturday"],"correct":0},{"question":"What should participants wear?","options":["Casual clothes","Business suits","Uniforms","Sport attire"],"correct":1},{"question":"What is the purpose of the gathering?","options":["Networking","Fundraising","Training","Celebration"],"correct":0},{"question":"What refreshments will be provided?","options":["Snacks and drinks","Full meals","Desserts only","Coffee and tea"],"correct":0},{"question":"How long will the event last?","options":["One hour","Three hours","Two hours","Four hours"],"correct":2},{"question":"What materials should attendees bring?","options":["Notebooks","Laptops","All of the above","None"],"correct":2},{"question":"What is the parking situation?","options":["Street parking available","Parking garage nearby","No parking allowed","Limited parking"],"correct":1},{"question":"What is the registration fee?","options":["$10","$50","$25","$0"],"correct":2},{"question":"Who can attend the event?","options":["Everyone","Members only","Invite-only","Students only"],"correct":0},{"question":"What is the theme of the conference?","options":["Innovation","Sustainability","Technology","Education"],"correct":1},{"question":"Where can participants find the agenda?","options":["On the website","At the entrance","In the email","All of the above"],"correct":3},{"question":"What should speakers prepare?","options":["Slides","Handouts","Both slides and handouts","Nothing"],"correct":2}]}', 12),
('en', 'B1', 'reading', 'Weather Report', 'Deep atmosphere', '{"type":"read_and_choose","instructions":"Analyze the weather.","passage":"A cold front is moving in from the north. Expect heavy rain and strong winds this evening. Temperatures will drop to five degrees. Driving will be dangerous due to low visibility. Stay indoors if possible.","exercises":[{"question":"Where is the front from?","options":["North","South","East","West"],"correct":0},{"question":"What is expected?","options":["Rain and wind","Sun","Snow","Heat"],"correct":0},{"question":"What is the temp?","options":["5 degrees","10 degrees","0 degrees","15 degrees"],"correct":0},{"question":"Is driving safe?","options":["No","Yes","Very","Maybe"],"correct":0},{"question":"What is suggested?","options":["Stay indoors","Go for run","Travel","Swim"],"correct":0},{"question":"What is the humidity level?","options":["30%","50%","70%","90%"],"correct":2},{"question":"Which direction is the wind blowing?","options":["Northeast","Southeast","Southwest","Northwest"],"correct":1},{"question":"What type of precipitation is likely?","options":["Sleet","Hail","Rain","Fog"],"correct":2},{"question":"What is the wind speed?","options":["5 km/h","15 km/h","25 km/h","35 km/h"],"correct":1},{"question":"What is the UV index today?","options":["Low","Moderate","High","Very High"],"correct":2},{"question":"What is the barometric pressure?","options":["1000 hPa","1010 hPa","1020 hPa","1030 hPa"],"correct":1},{"question":"What is the dew point?","options":["5 degrees","10 degrees","15 degrees","20 degrees"],"correct":1},{"question":"What is the expected visibility?","options":["1 km","5 km","10 km","20 km"],"correct":2},{"question":"What is the weather condition?","options":["Cloudy","Clear","Partly Cloudy","Overcast"],"correct":0},{"question":"What season is it currently?","options":["Spring","Summer","Autumn","Winter"],"correct":1},{"question":"What is the chance of precipitation?","options":["0%","20%","50%","80%"],"correct":3},{"question":"What is the condition of the air quality?","options":["Good","Moderate","Unhealthy","Hazardous"],"correct":1},{"question":"What is the expected temperature range?","options":["0-5 degrees","5-10 degrees","10-15 degrees","15-20 degrees"],"correct":2},{"question":"What is the expected cloud cover?","options":["Clear","Partly Cloudy","Mostly Cloudy","Overcast"],"correct":3},{"question":"What is the expected wind chill factor?","options":["-5 degrees","0 degrees","5 degrees","10 degrees"],"correct":0}]}', 13),
('en', 'B1', 'reading', 'Mystery Story', 'Inference practice', '{"type":"read_and_choose","instructions":"Solve the mini mystery.","passage":"The window was open, and the curtains were fluttering. The silver vase was missing from the table. There were muddy footprints on the carpet. The cat was sleeping peacefully on the sofa.","exercises":[{"question":"What was missing?","options":["Vase","Cat","Curtains","Table"],"correct":0},{"question":"Was the window closed?","options":["No, open","Yes","Unknown","Broken"],"correct":0},{"question":"What was on the carpet?","options":["Footprints","Water","Milk","Glass"],"correct":0},{"question":"Where was the cat?","options":["Sofa","Window","Table","Garden"],"correct":0},{"question":"Was the cat guilty?","options":["Probably not","Yes","Maybe","Always"],"correct":0},{"question":"Who was last seen in the room?","options":["John","Sarah","Michael","Emma"],"correct":1},{"question":"What time was the alarm set for?","options":["7 AM","8 AM","9 AM","10 AM"],"correct":0},{"question":"What did the detective find on the table?","options":["A note","A pen","A wallet","A book"],"correct":0},{"question":"Was there a security camera?","options":["Yes","No","Partially functioning","Unknown"],"correct":0},{"question":"What color was the missing item?","options":["Red","Blue","Green","Yellow"],"correct":2},{"question":"How did the detective enter the room?","options":["Through the door","Through the window","Through the ceiling","Through the floor"],"correct":0},{"question":"What did the witness hear?","options":["A scream","A laugh","A crash","A phone ringing"],"correct":0},{"question":"What was the weather like?","options":["Sunny","Rainy","Windy","Snowy"],"correct":1},{"question":"What did the detective conclude?","options":["It was an accident","It was a robbery","It was a prank","It was a setup"],"correct":1},{"question":"Where was the clue found?","options":["In the drawer","Under the bed","On the shelf","In the closet"],"correct":3},{"question":"Who has a motive?","options":["John","Sarah","Michael","Emma"],"correct":2},{"question":"What was the last thing that was heard?","options":["A door closing","Footsteps","A gunshot","A conversation"],"correct":0},{"question":"What type of item was stolen?","options":["Jewelry","Electronics","Cash","Clothing"],"correct":0},{"question":"What did the victim do last?","options":["Called a friend","Went to bed","Left the house","Took a shower"],"correct":2},{"question":"What was unusual about the scene?","options":["It was too clean","It was too messy","It smelled bad","It was dark"],"correct":1}]}', 14),
('en', 'B1', 'reading', 'Travel Blog', 'Vlogging style', '{"type":"read_and_choose","instructions":"Understanding tone.","passage":"I just arrived in Tokyo and it is incredible! The neon lights are everywhere. The food is so fresh and tasty. I am staying in a tiny hotel room, which is a bit strange, but everything else is perfect.","exercises":[{"question":"Where is the blogger?","options":["Tokyo","Paris","New York","London"],"correct":0},{"question":"How is the food?","options":["Fresh","Salty","Old","Bad"],"correct":0},{"question":"What is strange?","options":["Hotel room","Lights","Food","People"],"correct":0},{"question":"Are the lights bright?","options":["Yes, neon","No","Dark","Dim"],"correct":0},{"question":"Is the blogger happy?","options":["Yes","No","Angry","Sad"],"correct":0},{"question":"What is the weather like?","options":["Sunny","Rainy","Windy","Snowy"],"correct":1},{"question":"How does the blogger feel?","options":["Excited","Bored","Confused","Tired"],"correct":0},{"question":"What does the blogger recommend?","options":["A museum","A restaurant","A park","A hotel"],"correct":1},{"question":"What is unique about the city?","options":["Architecture","People","Transportation","Weather"],"correct":0},{"question":"How is the service?","options":["Friendly","Slow","Rude","Inattentive"],"correct":0},{"question":"What is the blogger''s favorite activity?","options":["Shopping","Sightseeing","Dining","Relaxing"],"correct":1},{"question":"What is the blogger''s first impression?","options":["Negative","Neutral","Positive","Curious"],"correct":2},{"question":"What does the blogger find interesting?","options":["History","Culture","Nature","Food"],"correct":1},{"question":"What is the atmosphere like?","options":["Lively","Quiet","Chaotic","Relaxed"],"correct":0},{"question":"What kind of people does the blogger meet?","options":["Friendly","Rude","Shy","Busy"],"correct":0},{"question":"How does the blogger describe the local culture?","options":["Rich","Boring","Confusing","Simple"],"correct":0},{"question":"What is the blogger''s mood during the trip?","options":["Happy","Sad","Angry","Anxious"],"correct":0},{"question":"What does the blogger think about the local customs?","options":["Fascinating","Annoying","Strange","Normal"],"correct":0},{"question":"How is the nightlife?","options":["Vibrant","Dull","Safe","Dangerous"],"correct":0},{"question":"What does the blogger say about the prices?","options":["Expensive","Affordable","Cheap","Overpriced"],"correct":1}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'B1', 'writing', 'Urban Description', 'Describe a city scene', '{"type":"guided_writing","instructions":"Answer with full sentences.","exercises":[{"question":"What can you see in a city?","starter":"In a city, I can see","example":"In a city, I can see tall buildings and busy streets.","hint":"Buildings and people"},{"question":"How is the noise?","starter":"The noise is","example":"The noise is very loud because of the cars.","hint":"Volume"},{"question":"Where do people work?","starter":"People work in","example":"People work in offices, shops, and banks.","hint":"Location"},{"question":"Do you like cities?","starter":"I like cities because","example":"I like cities because there is always something to do.","hint":"Personal opinion"},{"question":"What is a problem?","starter":"A problem in cities is","example":"A problem in cities is the air pollution.","hint":"Negative aspect"},{"question":"What do you find in a park?","starter":"In a park, I can find","example":"In a park, I can find green trees and colorful flowers.","hint":"Nature and activities"},{"question":"How does the weather feel?","starter":"The weather feels","example":"The weather feels warm and sunny today.","hint":"Temperature and conditions"},{"question":"Where do people relax?","starter":"People relax in","example":"People relax in gardens, cafes, and at the beach.","hint":"Locations for leisure"},{"question":"What types of transportation are there?","starter":"In the city, there are","example":"In the city, there are buses, trains, and bicycles.","hint":"Ways to travel"},{"question":"What do you hear in a busy market?","starter":"In a busy market, I can hear","example":"In a busy market, I can hear vendors calling and people chatting.","hint":"Sounds and activities"},{"question":"What do children do in a playground?","starter":"In a playground, children","example":"In a playground, children play on swings and climb on slides.","hint":"Activities for kids"},{"question":"How do people travel?","starter":"People travel by","example":"People travel by car, bus, or train.","hint":"Modes of transportation"},{"question":"What can you eat in a city?","starter":"In a city, I can eat","example":"In a city, I can eat pizza, sushi, and tacos.","hint":"Types of food"},{"question":"What do you see at a beach?","starter":"At the beach, I can see","example":"At the beach, I can see waves, sand, and people sunbathing.","hint":"Beach features"},{"question":"What activities happen in a community center?","starter":"In a community center, people participate in","example":"In a community center, people participate in classes and group events.","hint":"Social gatherings"},{"question":"What do you notice about the nightlife?","starter":"The nightlife is","example":"The nightlife is vibrant with music and dancing.","hint":"Evening activities"},{"question":"What kind of shops are in a city?","starter":"In a city, there are shops like","example":"In a city, there are shops like clothing stores and bookstores.","hint":"Types of stores"},{"question":"How do people feel during a festival?","starter":"During a festival, people feel","example":"During a festival, people feel excited and joyful.","hint":"Emotions and atmosphere"},{"question":"What do you see on a busy street?","starter":"On a busy street, I can see","example":"On a busy street, I can see cars, bicycles, and pedestrians.","hint":"Street activity"},{"question":"What can you smell in a restaurant?","starter":"In a restaurant, I can smell","example":"In a restaurant, I can smell delicious food and fresh bread.","hint":"Aromas"}]}', 6),
('en', 'B1', 'writing', 'Expressing Opinions', 'Write about technology', '{"type":"guided_writing","instructions":"Give your thoughts.","exercises":[{"question":"Is technology good?","starter":"I think technology is","example":"I think technology is very useful in daily life.","hint":"General view"},{"question":"Why?","starter":"It helps us to","example":"It helps us to communicate with people far away.","hint":"Reason"},{"question":"What is the best gadget?","starter":"The best gadget is","example":"The best gadget is the smartphone.","hint":"Choice"},{"question":"Any downsides?","starter":"One downside is","example":"One downside is that it can be addictive.","hint":"Negative"},{"question":"Future of tech?","starter":"In the future, I think","example":"In the future, I think we will have flying cars.","hint":"Prediction"},{"question":"Is social media beneficial?","starter":"I believe social media is","example":"I believe social media is a great way to stay connected with friends.","hint":"General view"},{"question":"Why?","starter":"It allows us to","example":"It allows us to share our experiences and updates instantly.","hint":"Reason"},{"question":"What is your favorite social media platform?","starter":"My favorite social media platform is","example":"My favorite social media platform is Instagram.","hint":"Choice"},{"question":"Is online shopping convenient?","starter":"I think online shopping is","example":"I think online shopping is very convenient for busy people.","hint":"General view"},{"question":"Why?","starter":"It saves us time because","example":"It saves us time because we can shop from home.","hint":"Reason"},{"question":"What is the best online store?","starter":"The best online store is","example":"The best online store is Amazon.","hint":"Choice"},{"question":"Are video games a good way to relax?","starter":"I think video games are","example":"I think video games are a fun way to unwind after a long day.","hint":"General view"},{"question":"Why?","starter":"They help us to","example":"They help us to escape reality for a while.","hint":"Reason"},{"question":"What is your favorite video game?","starter":"My favorite video game is","example":"My favorite video game is The Legend of Zelda.","hint":"Choice"},{"question":"Is learning a language online effective?","starter":"I believe learning a language online is","example":"I believe learning a language online is very effective with the right resources.","hint":"General view"},{"question":"Why?","starter":"It offers us flexibility because","example":"It offers us flexibility because we can learn at our own pace.","hint":"Reason"},{"question":"What is the best app for language learning?","starter":"The best app for language learning is","example":"The best app for language learning is Duolingo.","hint":"Choice"},{"question":"Are podcasts a good source of information?","starter":"I think podcasts are","example":"I think podcasts are an excellent way to learn while multitasking.","hint":"General view"},{"question":"Why?","starter":"They provide us with","example":"They provide us with diverse perspectives on various topics.","hint":"Reason"},{"question":"What is your favorite podcast?","starter":"My favorite podcast is","example":"My favorite podcast is ''Stuff You Should Know''.","hint":"Choice"}]}', 7),
('en', 'B1', 'writing', 'Giving Advice', 'Writing helpful tips', '{"type":"guided_writing","instructions":"Advise a friend.","exercises":[{"question":"Friend is tired?","starter":"You should","example":"You should go to bed earlier tonight.","hint":"Fatigue"},{"question":"Friend is bored?","starter":"Why don''t you","example":"Why don''t you start a new hobby?","hint":"Boredom"},{"question":"Friend is lost?","starter":"If I were you, I would","example":"If I were you, I would check the map.","hint":"Navigation"},{"question":"Friend is hungry?","starter":"You could","example":"You could order some pizza.","hint":"Hunger"},{"question":"Friend is sad?","starter":"It might be good to","example":"It might be good to talk to someone.","hint":"Mood"},{"question":"Friend is stressed?","starter":"You might want to","example":"You might want to try some meditation.","hint":"Stress relief"},{"question":"Friend is feeling lonely?","starter":"Have you considered","example":"Have you considered joining a club?","hint":"Socializing"},{"question":"Friend is hungry?","starter":"Why don''t you","example":"Why don''t you grab a snack?","hint":"Hunger"},{"question":"Friend is anxious about an exam?","starter":"If I were you, I would","example":"If I were you, I would study a bit more.","hint":"Exam preparation"},{"question":"Friend is feeling unwell?","starter":"You should","example":"You should see a doctor.","hint":"Health"},{"question":"Friend is struggling with time management?","starter":"You might want to","example":"You might want to create a schedule.","hint":"Organization"},{"question":"Friend is planning a trip?","starter":"Have you thought about","example":"Have you thought about making an itinerary?","hint":"Travel planning"},{"question":"Friend is trying to save money?","starter":"You could consider","example":"You could consider making a budget.","hint":"Financial planning"},{"question":"Friend is feeling uninspired?","starter":"Why don''t you","example":"Why don''t you visit an art gallery?","hint":"Inspiration"},{"question":"Friend is having trouble sleeping?","starter":"You should","example":"You should avoid screens before bedtime.","hint":"Sleep hygiene"},{"question":"Friend is looking for a workout plan?","starter":"If I were you, I would","example":"If I were you, I would consult a trainer.","hint":"Fitness"},{"question":"Friend is feeling overwhelmed?","starter":"You might want to","example":"You might want to take breaks regularly.","hint":"Overwhelm management"},{"question":"Friend is considering a career change?","starter":"Have you thought about","example":"Have you thought about networking in your desired field?","hint":"Career advice"},{"question":"Friend is looking for new recipes?","starter":"You could try","example":"You could try searching online for easy recipes.","hint":"Cooking"},{"question":"Friend is feeling under the weather?","starter":"You should","example":"You should rest and drink plenty of fluids.","hint":"Recovery"}]}', 8),
('en', 'B1', 'writing', 'Formal Email', 'Practice business writing', '{"type":"guided_writing","instructions":"Complete the email.","exercises":[{"question":"Subject line?","starter":"Subject:","example":"Subject: Meeting Request","hint":"Title"},{"question":"Opening?","starter":"Dear ","example":"Dear Mr. Smith,","hint":"Greeting"},{"question":"Reason to write?","starter":"I am writing to","example":"I am writing to inquire about the job.","hint":"Purpose"},{"question":"Attachment?","starter":"I have attached my","example":"I have attached my CV for your review.","hint":"Files"},{"question":"Closing?","starter":"Sincerely,","example":"Sincerely, John Doe.","hint":"Sign-off"},{"question":"Closing?","starter":"Sincerely,","example":"Sincerely, John Doe","hint":"Farewell phrase"},{"question":"Request for information?","starter":"Could you please provide me with","example":"Could you please provide me with the latest project updates?","hint":"What you want to know"},{"question":"Expressing gratitude?","starter":"Thank you for","example":"Thank you for your prompt response.","hint":"Showing appreciation"},{"question":"Offering assistance?","starter":"If you need any help,","example":"If you need any help, please feel free to reach out.","hint":"Making yourself available"},{"question":"Follow-up question?","starter":"I would like to follow up on","example":"I would like to follow up on our last conversation.","hint":"Continuing the discussion"},{"question":"Expressing urgency?","starter":"It is important that","example":"It is important that we address this issue as soon as possible.","hint":"Indicating time sensitivity"},{"question":"Subject of discussion?","starter":"Regarding the","example":"Regarding the upcoming conference,","hint":"What the email is about"},{"question":"Requesting a meeting?","starter":"I would like to schedule a meeting to","example":"I would like to schedule a meeting to discuss our collaboration.","hint":"Setting up a time"},{"question":"Providing feedback?","starter":"I would like to share my thoughts on","example":"I would like to share my thoughts on the proposal you submitted.","hint":"Giving your opinion"},{"question":"Expressing concern?","starter":"I am concerned about","example":"I am concerned about the recent delays in the project.","hint":"Addressing an issue"},{"question":"Mentioning attachments?","starter":"Attached you will find","example":"Attached you will find the report for your review.","hint":"Files included"},{"question":"Confirming receipt?","starter":"I would like to confirm that I received","example":"I would like to confirm that I received your email.","hint":"Acknowledging communication"},{"question":"Expressing interest?","starter":"I am very interested in","example":"I am very interested in the internship opportunity at your company.","hint":"Showing enthusiasm"},{"question":"Clarifying information?","starter":"Could you please clarify","example":"Could you please clarify the deadline for the project?","hint":"Seeking clarity"},{"question":"Ending with a reminder?","starter":"Just a quick reminder that","example":"Just a quick reminder that the deadline is next week.","hint":"Highlighting important dates"}]}', 9),
('en', 'B1', 'writing', 'Job Application', 'Short bio for work', '{"type":"guided_writing","instructions":"Write a short profile.","exercises":[{"question":"Your skills?","starter":"I am skilled in","example":"I am skilled in coding and design.","hint":"Abilities"},{"question":"Experience?","starter":"I have worked for","example":"I have worked for three years in IT.","hint":"History"},{"question":"Why this job?","starter":"I want this job because","example":"I want this job because I love challenges.","hint":"Motivation"},{"question":"Strengths?","starter":"My main strength is","example":"My main strength is problem solving.","hint":"Positives"},{"question":"Availability?","starter":"I can start","example":"I can start from next month.","hint":"Timing"},{"question":"Your education?","starter":"I graduated from","example":"I graduated from Harvard University with a degree in Economics.","hint":"Academic background"},{"question":"Hobbies?","starter":"In my free time, I enjoy","example":"In my free time, I enjoy hiking and photography.","hint":"Interests"},{"question":"Strengths?","starter":"My greatest strengths are","example":"My greatest strengths are my communication skills and adaptability.","hint":"Personal qualities"},{"question":"Languages spoken?","starter":"I speak","example":"I speak English and Spanish fluently.","hint":"Language skills"},{"question":"What makes you unique?","starter":"What sets me apart is","example":"What sets me apart is my creative problem-solving approach.","hint":"Distinctive traits"},{"question":"Future goals?","starter":"In the future, I aspire to","example":"In the future, I aspire to lead a team in a successful startup.","hint":"Aspirations"},{"question":"Work style?","starter":"I prefer to work","example":"I prefer to work collaboratively in a team environment.","hint":"Work preferences"},{"question":"Key achievements?","starter":"One of my key achievements is","example":"One of my key achievements is launching a successful marketing campaign.","hint":"Accomplishments"},{"question":"Challenges faced?","starter":"A challenge I faced was","example":"A challenge I faced was managing tight deadlines while maintaining quality.","hint":"Obstacles"},{"question":"Professional development?","starter":"I am currently pursuing","example":"I am currently pursuing certifications in project management.","hint":"Learning goals"},{"question":"Networking?","starter":"I believe networking is important because","example":"I believe networking is important because it opens up new opportunities.","hint":"Connections"},{"question":"Work-life balance?","starter":"I maintain a work-life balance by","example":"I maintain a work-life balance by setting clear boundaries and prioritizing self-care.","hint":"Lifestyle"},{"question":"Feedback received?","starter":"Feedback I have received includes","example":"Feedback I have received includes praise for my leadership skills.","hint":"Reviews"},{"question":"Favorite project?","starter":"My favorite project was","example":"My favorite project was developing an app that helps users track their fitness goals.","hint":"Projects"},{"question":"Volunteering experience?","starter":"I have volunteered at","example":"I have volunteered at a local animal shelter for two years.","hint":"Community service"}]}', 10),
('en', 'B1', 'writing', 'Comparison', 'Compare two things', '{"type":"guided_writing","instructions":"Write comparisons.","exercises":[{"question":"City vs Country?","starter":"The city is","example":"The city is noisier than the countryside.","hint":"Environment"},{"question":"Book vs Movie?","starter":"A book is usually","example":"A book is usually more detailed than a movie.","hint":"Media"},{"question":"Summer vs Winter?","starter":"Summer is","example":"Summer is much hotter than winter.","hint":"Seasons"},{"question":"Tea vs Coffee?","starter":"Tea is","example":"Tea is healthier but coffee gives more energy.","hint":"Drinks"},{"question":"Plane vs Train?","starter":"A plane is","example":"A plane is faster but a train is more relaxing.","hint":"Travel"},{"question":"Tea vs Coffee?","starter":"Tea is often","example":"Tea is often more soothing than coffee.","hint":"Beverages"},{"question":"Laptop vs Desktop?","starter":"A laptop is typically","example":"A laptop is typically more portable than a desktop.","hint":"Technology"},{"question":"Ocean vs Lake?","starter":"The ocean is usually","example":"The ocean is usually larger than a lake.","hint":"Geography"},{"question":"Dog vs Cat?","starter":"A dog is commonly","example":"A dog is commonly more social than a cat.","hint":"Pets"},{"question":"Jazz vs Rock?","starter":"Jazz music is often","example":"Jazz music is often more improvisational than rock.","hint":"Music"},{"question":"School vs University?","starter":"University is generally","example":"University is generally more advanced than school.","hint":"Education"},{"question":"Phone vs Tablet?","starter":"A tablet is typically","example":"A tablet is typically better for reading than a phone.","hint":"Devices"},{"question":"Mountain vs Hill?","starter":"A mountain is usually","example":"A mountain is usually taller than a hill.","hint":"Landforms"},{"question":"Basketball vs Soccer?","starter":"Basketball is generally","example":"Basketball is generally played indoors more than soccer.","hint":"Sports"},{"question":"Cooking at Home vs Dining Out?","starter":"Cooking at home is often","example":"Cooking at home is often healthier than dining out.","hint":"Food"},{"question":"Winter Sports vs Summer Sports?","starter":"Winter sports are usually","example":"Winter sports are usually more challenging than summer sports.","hint":"Activities"},{"question":"Online Learning vs Traditional Learning?","starter":"Online learning can be","example":"Online learning can be more flexible than traditional learning.","hint":"Education"},{"question":"Gardening vs Farming?","starter":"Gardening is often","example":"Gardening is often on a smaller scale than farming.","hint":"Agriculture"},{"question":"Vacationing at the Beach vs the Mountains?","starter":"Vacationing at the beach is usually","example":"Vacationing at the beach is usually more relaxing than in the mountains.","hint":"Travel"},{"question":"Reading Fiction vs Non-Fiction?","starter":"Reading fiction is often","example":"Reading fiction is often more entertaining than reading non-fiction.","hint":"Literature"}]}', 11),
('en', 'B1', 'writing', 'Summarizing', 'Condensing information', '{"type":"guided_writing","instructions":"Condense the story.","exercises":[{"question":"What happened first?","starter":"First, the character","example":"First, the character found a map.","hint":"Start"},{"question":"What was the middle?","starter":"Then, they traveled","example":"Then, they traveled to the island.","hint":"Action"},{"question":"What was the climax?","starter":"Suddenly, they found","example":"Suddenly, they found the treasure.","hint":"Peak"},{"question":"How did it end?","starter":"In the end, everyone","example":"In the end, everyone was happy.","hint":"Conclusion"},{"question":"Moral?","starter":"The moral is","example":"The moral is that courage pays off.","hint":"Lesson"},{"question":"What was the character''s goal?","starter":"The character wanted to","example":"The character wanted to find the lost city.","hint":"Objective"},{"question":"What obstacle did they face?","starter":"However, they encountered","example":"However, they encountered a fierce storm.","hint":"Challenge"},{"question":"How did they seek help?","starter":"So, they asked","example":"So, they asked a wise elder for guidance.","hint":"Support"},{"question":"What discovery did they make?","starter":"Eventually, they discovered","example":"Eventually, they discovered ancient ruins.","hint":"Finding"},{"question":"What did they learn from their journey?","starter":"Ultimately, they learned","example":"Ultimately, they learned the value of teamwork.","hint":"Lesson"},{"question":"What was the setting?","starter":"The story took place in","example":"The story took place in a dense jungle.","hint":"Location"},{"question":"Who was their companion?","starter":"Along the way, they were joined by","example":"Along the way, they were joined by a brave warrior.","hint":"Friend"},{"question":"What was the character''s reaction to danger?","starter":"When danger appeared, they","example":"When danger appeared, they stood their ground.","hint":"Response"},{"question":"What was the result of their adventure?","starter":"In the end, they","example":"In the end, they found peace and happiness.","hint":"Outcome"},{"question":"What did they find at the end?","starter":"Finally, they uncovered","example":"Finally, they uncovered a hidden treasure.","hint":"Conclusion"},{"question":"What was their initial emotion?","starter":"At first, they felt","example":"At first, they felt excitement and fear.","hint":"Emotion"},{"question":"What did they overcome?","starter":"They had to overcome","example":"They had to overcome their fears and doubts.","hint":"Challenge"},{"question":"What was a major turning point?","starter":"Suddenly, they realized","example":"Suddenly, they realized they had the strength to continue.","hint":"Change"},{"question":"What did they promise to do?","starter":"They promised to","example":"They promised to protect the treasure they found.","hint":"Commitment"},{"question":"What was the final challenge?","starter":"At the last moment, they faced","example":"At the last moment, they faced a formidable enemy.","hint":"Climax"}]}', 12),
('en', 'B1', 'writing', 'Future Intentions', 'Writing about goals', '{"type":"guided_writing","instructions":"Predict your future.","exercises":[{"question":"Learning goals?","starter":"I plan to learn","example":"I plan to learn to speak French.","hint":"Knowledge"},{"question":"Career goals?","starter":"I hope to become","example":"I hope to become a manager.","hint":"Work"},{"question":"Travel goals?","starter":"I am going to visit","example":"I am going to visit Japan.","hint":"Trips"},{"question":"Health goals?","starter":"I will try to","example":"I will try to exercise every day.","hint":"Body"},{"question":"Personal goals?","starter":"I want to","example":"I want to be more patient.","hint":"Self"},{"question":"Education goals?","starter":"I want to graduate from","example":"I want to graduate from university.","hint":"Academic achievements"},{"question":"Health goals?","starter":"I plan to start","example":"I plan to start a fitness routine.","hint":"Wellness"},{"question":"Hobby goals?","starter":"I aim to learn","example":"I aim to learn how to play the guitar.","hint":"Leisure activities"},{"question":"Financial goals?","starter":"I hope to save","example":"I hope to save money for a house.","hint":"Savings"},{"question":"Social goals?","starter":"I am going to make","example":"I am going to make new friends.","hint":"Relationships"},{"question":"Creative goals?","starter":"I want to create","example":"I want to create my own website.","hint":"Projects"},{"question":"Technology goals?","starter":"I hope to master","example":"I hope to master programming skills.","hint":"Tech skills"},{"question":"Community goals?","starter":"I plan to volunteer at","example":"I plan to volunteer at a local shelter.","hint":"Giving back"},{"question":"Environmental goals?","starter":"I want to contribute to","example":"I want to contribute to recycling efforts.","hint":"Sustainability"},{"question":"Cultural goals?","starter":"I am going to explore","example":"I am going to explore different cultures.","hint":"Diversity"},{"question":"Skill development goals?","starter":"I hope to improve my","example":"I hope to improve my writing skills.","hint":"Personal development"},{"question":"Lifestyle goals?","starter":"I want to adopt","example":"I want to adopt a healthier lifestyle.","hint":"Living well"},{"question":"Spiritual goals?","starter":"I plan to practice","example":"I plan to practice mindfulness.","hint":"Inner peace"},{"question":"Family goals?","starter":"I hope to spend more time with","example":"I hope to spend more time with my family.","hint":"Relationships"},{"question":"Personal growth goals?","starter":"I aim to become more","example":"I aim to become more confident.","hint":"Self-improvement"}]}', 13),
('en', 'B1', 'writing', 'Personal Experience', 'Writing about the past', '{"type":"guided_writing","instructions":"Share a memory.","exercises":[{"question":"When did it happen?","starter":"It happened","example":"It happened last summer.","hint":"Time"},{"question":"Where?","starter":"I was in","example":"I was in a small town.","hint":"Place"},{"question":"What happened?","starter":"I saw","example":"I saw a very famous actor.","hint":"Event"},{"question":"How did you feel?","starter":"I felt","example":"I felt extremely excited.","hint":"Emotion"},{"question":"Why do you remember?","starter":"I remember it because","example":"I remember it because it was so rare.","hint":"Impact"},{"question":"Who was with you?","starter":"I was with","example":"I was with my best friend.","hint":"Companion"},{"question":"How did you feel?","starter":"I felt","example":"I felt extremely happy.","hint":"Emotion"},{"question":"What were you doing before?","starter":"Before this, I was","example":"Before this, I was studying for my exams.","hint":"Activity"},{"question":"What did you learn?","starter":"I learned","example":"I learned how to cook a new dish.","hint":"Lesson"},{"question":"What did you eat?","starter":"I ate","example":"I ate delicious pizza.","hint":"Food"},{"question":"What did you see?","starter":"I saw","example":"I saw beautiful landscapes.","hint":"Sight"},{"question":"What was the weather like?","starter":"The weather was","example":"The weather was sunny and warm.","hint":"Condition"},{"question":"What did you hear?","starter":"I heard","example":"I heard my favorite song playing.","hint":"Sound"},{"question":"What was special about the day?","starter":"The day was special because","example":"The day was special because it was my birthday.","hint":"Occasion"},{"question":"What did you wear?","starter":"I wore","example":"I wore a bright red dress.","hint":"Clothing"},{"question":"What did you bring?","starter":"I brought","example":"I brought a camera to capture moments.","hint":"Item"},{"question":"What did you say?","starter":"I said","example":"I said hello to everyone I met.","hint":"Speech"},{"question":"What was the highlight?","starter":"The highlight of the day was","example":"The highlight of the day was the fireworks display.","hint":"Moment"},{"question":"What did you take home?","starter":"I took home","example":"I took home some wonderful memories.","hint":"Memory"},{"question":"What made you laugh?","starter":"I laughed when","example":"I laughed when my friend made a funny joke.","hint":"Humor"},{"question":"What was your favorite part?","starter":"My favorite part was","example":"My favorite part was the dance party.","hint":"Activity"}]}', 14),
('en', 'B1', 'writing', 'Unscramble Sentences', 'Complex sentence structure', '{"type":"unscramble","instructions":"Unscramble the B1 level sentence.","exercises":[{"scrambled":"been have I studying for English years three.","expected":"I have been studying English for three years.","hint":"Present perfect continuous"},{"scrambled":"If it tomorrow rains, will we stay home.","expected":"If it rains tomorrow, we will stay home.","hint":"Conditionals"},{"scrambled":"The movie which saw we was yesterday great.","expected":"The movie which we saw yesterday was great.","hint":"Relative clauses"},{"scrambled":"I don''t know where they going are now.","expected":"I don''t know where they are going now.","hint":"Indirect questions"},{"scrambled":"She said that would she come later.","expected":"She said that she would come later.","hint":"Reported speech"},{"scrambled":"every day I breakfast eat at 8 o''clock.","expected":"I eat breakfast every day at 8 o''clock.","hint":"Present simple"},{"scrambled":"They playing football are now in the park.","expected":"They are playing football now in the park.","hint":"Present continuous"},{"scrambled":"She will finished her homework by 5 PM.","expected":"She will have finished her homework by 5 PM.","hint":"Future perfect"},{"scrambled":"We have seen that movie before last week.","expected":"We saw that movie last week.","hint":"Past simple"},{"scrambled":"My brother to the gym every weekend goes.","expected":"My brother goes to the gym every weekend.","hint":"Present simple"},{"scrambled":"When you finish your work, we can go dinner.","expected":"When you finish your work, we can go to dinner.","hint":"Prepositions"},{"scrambled":"She didn''t like the book I gave her.","expected":"She didn''t like the book that I gave her.","hint":"Relative clauses"},{"scrambled":"I will call you if I get home early.","expected":"I will call you if I get home early.","hint":"Conditionals"},{"scrambled":"The restaurant where we had dinner was amazing.","expected":"The restaurant where we had dinner was amazing.","hint":"Relative clauses"},{"scrambled":"He always takes the bus to work in the mornings.","expected":"He always takes the bus to work in the mornings.","hint":"Present simple"},{"scrambled":"They were playing video games when I arrived.","expected":"They were playing video games when I arrived.","hint":"Past continuous"},{"scrambled":"I bought a new phone last week.","expected":"I bought a new phone last week.","hint":"Past simple"},{"scrambled":"If it snows, we will build a snowman.","expected":"If it snows, we will build a snowman.","hint":"Conditionals"},{"scrambled":"He has been working here since two years.","expected":"He has been working here for two years.","hint":"Present perfect continuous"},{"scrambled":"The teacher gave us a lot of homework yesterday.","expected":"The teacher gave us a lot of homework yesterday.","hint":"Past simple"}]}', 15);
